      stableCount: 0,
      transitionCount: 0,
      loadingCount: 0,
      typingCount: 0,
      dimmedCount: 0
    });
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');

    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current++;
    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
      setIsDragging(true);
    }
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current--;
    if (dragCounter.current === 0) {
      setIsDragging(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    dragCounter.current = 0;

    const file = e.dataTransfer.files?.[0];
    if (file) handleFile(file);
  };

  const getFrameMetadata = async (time: number): Promise<{ 
    hash: string, 
    metrics: { blurScore: number, edgeIntensity: number }, 
    isLoading: boolean,
    overlay: { isDimmed: boolean, hasPopup: boolean }
  }> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return { hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } };

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) return resolve({ hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } });

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const isLoading = detectLoadingState(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, isLoading, overlay });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const extracted: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let localStats = { 
      totalFramesAnalyzed: 0, 
      duplicateCount: 0, 
      blurryCount: 0, 
      stableCount: 0, 
      transitionCount: 0, 
      loadingCount: 0, 
      typingCount: 0, 
      dimmedCount: 0 
    };

    /**
     * candidateRef helps us implement the "Ignore process of filing the form" requirement.
     * We hold onto a "stable" frame. If subsequent frames are just "typing" variants of it,
     * we replace the candidate with the newest one (the most filled version).
     * We only commit the candidate when a SIGNIFICANT change occurs.
     */
    let currentCandidate: ExtractedFrame | null = null;

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      const metadata = await getFrameMetadata(time);
      localStats.totalFramesAnalyzed++;
      setProgress(Math.min(100, (time / duration) * 100));

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = hammingDistance(metadata.hash, post.hash);
      const isSharp = metadata.metrics.blurScore > BLUR_THRESHOLD;
      const isSettled = postDiff <= 1; 

      let filterReason: ExtractedFrame['filterReason'] = undefined;

      if (metadata.isLoading) {
        filterReason = 'loading';
        localStats.loadingCount++;
      } else if (!isSharp) {
        filterReason = 'blurry';
        localStats.blurryCount++;
      } else if (!isSettled) {
        filterReason = 'transition';
        localStats.transitionCount++;
      } else if (metadata.overlay.isDimmed && !metadata.overlay.hasPopup) {
        // Requirement 3: Ignore dimmed/low-opacity layers unless there's a popup
        filterReason = 'dimmed';
        localStats.dimmedCount++;
      } else {
        // Check uniqueness and typing
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        const newFrame: ExtractedFrame = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: true,
          isUnique: true
        };

        if (!currentCandidate) {
          // If no previous candidate, check if this is a duplicate of something already committed
          let isDuplicate = false;
          for (const f of extracted) {
            if (hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD) {
              isDuplicate = true;
              break;
            }
          }
          if (isDuplicate) {
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else {
            currentCandidate = newFrame;
          }
        } else {
          const distFromCandidate = hammingDistance(metadata.hash, currentCandidate.hash);

          if (distFromCandidate <= SIMILARITY_THRESHOLD) {
            // Perfect duplicate of current pending candidate, just skip
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else if (distFromCandidate <= TYPING_THRESHOLD) {
            // Requirement 1 & 2: Typing / Minor form filling change.
            // Replace current candidate with this newer, more "filled" version.
            currentCandidate = newFrame;
            // We don't mark it as 'typing' for the filtered list because we ARE using the data to update the candidate
          } else {
            // Major change! Commit the last state of the previous candidate and start fresh.
            extracted.push(currentCandidate);
            localStats.stableCount++;

            // Now check if the new frame is a duplicate of any existing COMMITTED frames
            let isDuplicate = false;
            for (const f of extracted) {
               if (hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD) {
                 isDuplicate = true;
                 break;
               }
            }

            if (isDuplicate) {
              filterReason = 'duplicate';
              localStats.duplicateCount++;
              currentCandidate = null;
            } else {
              currentCandidate = newFrame;
            }
          }
        }
      }

      if (filterReason) {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        filtered.push({
          id: `filtered-${Math.random().toString(36).substr(2, 9)}`,
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: filterReason !== 'transition',
          isUnique: false,
          filterReason
        });
      }

      setStats({ ...localStats });
    }

    // Don't forget the final candidate
    if (currentCandidate) {
      extracted.push(currentCandidate);
      localStats.stableCount++;
    }

    setFrames(extracted);
    setFilteredFrames(filtered);
    setSelectedIds(new Set());
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
    setViewMode('valid');
    setStats({ ...localStats });
  };

  const captureManualSnapshot = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const time = video.currentTime;
    const metadata = await getFrameMetadata(time);

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/png');

    const manualFrame: ExtractedFrame = {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: time,
      dataUrl,
      blurScore: metadata.metrics.blurScore,
      hash: metadata.hash,
      isStable: true,
      isUnique: true
    };

    setFrames(prev => [...prev, manualFrame].sort((a, b) => a.timestamp - b.timestamp));
    setSelectedIds(prev => new Set([...prev, manualFrame.id]));
  };

  const deleteFrame = (id: string) => {
    setFrames(prev => prev.filter(f => f.id !== id));
    setFilteredFrames(prev => prev.filter(f => f.id !== id));
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const restoreFrame = (id: string) => {
    const frameToRestore = filteredFrames.find(f => f.id === id);
    if (frameToRestore) {
      setFilteredFrames(prev => prev.filter(f => f.id !== id));
      const restored = { ...frameToRestore, filterReason: 'manual-restored' as const };
      const newFrames = [...frames, restored].sort((a, b) => a.timestamp - b.timestamp);
      setFrames(newFrames);
    }
  };

  const restoreSelectedFrames = () => {
    const toRestore = filteredFrames.filter(f => selectedIds.has(f.id));
    if (toRestore.length === 0) return;

    const restoreIds = new Set(toRestore.map(f => f.id));
    setFilteredFrames(prev => prev.filter(f => !restoreIds.has(f.id)));

    const restoredWithStatus = toRestore.map(f => ({
      ...f,
      filterReason: 'manual-restored' as const
    }));

    const newFrames = [...frames, ...restoredWithStatus].sort((a, b) => a.timestamp - b.timestamp);
    setFrames(newFrames);
    setViewMode('valid');
  };

  const toggleFrameSelection = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const toggleAllSelection = (selected: boolean) => {
    const currentList = activeFrames;
    if (selected) {
      setSelectedIds(new Set([...selectedIds, ...currentList.map(f => f.id)]));
    } else {
      const next = new Set(selectedIds);
      currentList.forEach(f => next.delete(f.id));
      setSelectedIds(next);
    }
  };

  const convertImage = (dataUrl: string, format: 'png' | 'jpeg', quality: number): Promise<string> => {
    return new Promise((resolve) => {
      if (format === 'png') {
        resolve(dataUrl);
        return;
      }
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = img.width;
        canvas.height = img.height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0);
          resolve(canvas.toDataURL('image/jpeg', quality));
        } else {
          resolve(dataUrl);
        }
      };
      img.src = dataUrl;
    });
  };

  const downloadFrame = async (frame: ExtractedFrame) => {
    const formattedUrl = await convertImage(frame.dataUrl, exportFormat, exportQuality);
    const link = document.createElement('a');
    link.download = `frame-${frame.timestamp.toFixed(2)}s.${exportFormat}`;
    link.href = formattedUrl;
    link.click();
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0 || !videoFile) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const allPossibleFrames = [...frames, ...filteredFrames];
      const sortedSelectedFrames = allPossibleFrames
        .filter(f => selectedIds.has(f.id))
        .sort((a, b) => a.timestamp - b.timestamp);

      for (let i = 0; i < sortedSelectedFrames.length; i++) {
        const frame = sortedSelectedFrames[i];
        const formattedUrl = await convertImage(frame.dataUrl, exportFormat, exportQuality);
        const base64Data = formattedUrl.split(',')[1];
        zip.file(`${i + 1}.${exportFormat}`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      const videoBaseName = videoFile.name.replace(/\.[^/.]+$/, "");
      link.download = `${videoBaseName}.zip`;
      link.click();
    } catch (error) {
      console.error("Download Error:", error);
    } finally {
      setIsDownloading(false);
    }
  };

  const activeFrames = (() => {
    if (viewMode === 'valid') return frames;
    if (viewMode === 'duplicates') return filteredFrames.filter(f => f.filterReason === 'duplicate');
    if (viewMode === 'transitions') return filteredFrames.filter(f => f.filterReason === 'transition');
    if (viewMode === 'blurry') return filteredFrames.filter(f => f.filterReason === 'blurry');
    if (viewMode === 'loading') return filteredFrames.filter(f => f.filterReason === 'loading');
    if (viewMode === 'typing') return filteredFrames.filter(f => f.filterReason === 'typing');
    if (viewMode === 'dimmed') return filteredFrames.filter(f => f.filterReason === 'dimmed');
    return [];
  })();

  const selectedInActiveCount = activeFrames.filter(f => selectedIds.has(f.id)).length;

  return (
    <div 
      className="max-w-[1600px] mx-auto px-4 py-8 sm:px-6 lg:px-8 min-h-screen flex flex-col relative"
      onDragEnter={handleDragEnter}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <AnimatePresence>
        {isDragging && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[200] bg-blue-600/20 backdrop-blur-md flex items-center justify-center pointer-events-none"
          >
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="bg-gray-900/90 border-4 border-dashed border-blue-500 rounded-[3rem] p-12 flex flex-col items-center gap-6 shadow-2xl"
            >
              <div className="w-24 h-24 bg-blue-600/20 rounded-full flex items-center justify-center">
                <svg className="w-12 h-12 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
              </div>
              <div className="text-center">
                <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Drop to Upload</h2>
                <p className="text-blue-400 font-bold text-sm mt-2 opacity-80 uppercase tracking-widest">Any video format supported</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6 flex-shrink-0">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">
            Anatomi <span className="text-blue-500">Video Editor</span>
          </h1>
          <p className="text-gray-400 text-xs mt-1">
            High-precision extraction engine for UI/UX audits and video analysis.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <button
            onClick={() => setIsChatOpen(true)}
            className="px-5 py-2.5 rounded-xl font-bold bg-gray-800 hover:bg-gray-700 text-white border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm shadow-lg"
          >
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
            </svg>
            <span>AI Assistant</span>
          </button>

          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            <span className="font-semibold">Upload Video</span>
          </label>

          <button 
            disabled={!videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)}
            onClick={processVideo}
            className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg text-sm ${
              !videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed opacity-50'
                : 'bg-blue-600 hover:bg-blue-500 text-white active:scale-95'
            }`}
          >
            {status === ProcessingStatus.IDLE || status === ProcessingStatus.COMPLETED ? (
              <>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                </svg>
                <span>Extract Frames</span>
              </>
            ) : (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                <span>Analyzing...</span>
              </>
            )}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0 mb-20">
        <div className="lg:col-span-3 flex flex-col gap-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl flex flex-col">
            <h2 className="text-xs font-black mb-3 flex items-center gap-2 uppercase tracking-widest text-gray-500">
              <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              Input Source
            </h2>

            <div className="bg-black rounded-xl overflow-hidden border border-gray-800 relative shadow-2xl transition-all duration-500 mb-4">
              {videoUrl ? (
                <video ref={videoRef} src={videoUrl} className="w-full h-auto block object-contain" controls />
              ) : (
                <div className="w-full aspect-video flex flex-col items-center justify-center text-gray-600 text-[10px] italic p-6 text-center gap-3">
                  <div className="w-12 h-12 rounded-full border border-gray-800 flex items-center justify-center text-gray-700">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                  </div>
                  <span className="uppercase font-black tracking-widest leading-relaxed">
                    Drop video here <br/> or click upload
                  </span>
                </div>
              )}
            </div>

            {status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED && (
               <div className="mb-4 p-3 bg-gray-950/50 rounded-xl border border-gray-800/50">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[9px] font-black text-blue-400 uppercase tracking-widest animate-pulse">Scanning Content</span>
                    <span className="text-[9px] font-black text-white">{Math.round(progress)}%</span>
                  </div>
                  <div className="w-full bg-gray-800 rounded-full h-1.5 overflow-hidden">
                    <motion.div 
                      initial={{ width: 0 }}
                      animate={{ width: `${progress}%` }}
                      className="bg-blue-500 h-full shadow-[0_0_8px_rgba(59,130,246,0.5)]"
                    />
                  </div>
               </div>
            )}

            <canvas ref={canvasRef} className="hidden" />

            <div className="mt-0 space-y-3">
              <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => setViewMode('valid')}
                  className={`flex flex-col items-start p-3 rounded-xl border transition-all text-left group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600' : 'bg-gray-800/50 border-gray-700/50'}`}
                >
                  <div className={`text-lg font-bold ${viewMode === 'valid' ? 'text-blue-400' : 'text-gray-300'}`}>{stats.stableCount}</div>
                  <div className="text-[8px] text-gray-500 uppercase font-black">Valid</div>
                </button>
                <button 
                  onClick={() => setViewMode('duplicates')}
                  className={`flex flex-col items-start p-3 rounded-xl border transition-all text-left group ${viewMode !== 'valid' ? 'bg-orange-600/10 border-orange-600' : 'bg-gray-800/50 border-gray-700/50'}`}
                >
                  <div className={`text-lg font-bold ${viewMode !== 'valid' ? 'text-orange-400' : 'text-gray-300'}`}>{filteredFrames.length}</div>
                  <div className="text-[8px] text-gray-500 uppercase font-black">Filtered</div>
                </button>
              </div>
              <div className="p-3 bg-gray-800/30 rounded-xl border border-gray-700/50 text-[9px] space-y-1 overflow-y-auto max-h-[160px] no-scrollbar">
                 <button onClick={() => setViewMode('duplicates')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'duplicates' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Duplicates</span>
                    <span>{stats.duplicateCount}</span>
                 </button>
                 <button onClick={() => setViewMode('transitions')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'transitions' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Transitions</span>
                    <span>{stats.transitionCount}</span>
                 </button>
                 <button onClick={() => setViewMode('blurry')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'blurry' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Blurry</span>
                    <span>{stats.blurryCount}</span>
                 </button>
                 <button onClick={() => setViewMode('loading')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'loading' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Loading</span>
                    <span>{stats.loadingCount}</span>
                 </button>
                 <button onClick={() => setViewMode('typing')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'typing' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Typing</span>
                    <span>{stats.typingCount}</span>
                 </button>
                 <button onClick={() => setViewMode('dimmed')} className={`flex justify-between w-full font-bold uppercase tracking-widest transition-colors p-1 rounded hover:bg-gray-800/50 ${viewMode === 'dimmed' ? 'text-blue-400 bg-gray-800' : 'text-gray-500 hover:text-gray-300'}`}>
                    <span>Dimmed</span>
                    <span>{stats.dimmedCount}</span>
                 </button>
              </div>
            </div>
          </section>
        </div>

        <div className="lg:col-span-9 flex flex-col gap-4 min-h-0">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex-shrink-0">
            <div className="flex flex-col gap-2">
              <div className="flex items-center gap-3">
                <h2 className="text-xl font-bold text-white capitalize">
