              {viewMode === 'filtered' && selectedInActiveCount > 0 && <button onClick={restoreSelectedFrames} className="px-4 py-2 rounded-xl bg-blue-600 text-white text-[10px] uppercase font-bold">Restore</button>}
            </div>
          </div>
          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const next = new Set(prev); next.has(id) ? next.delete(id) : next.add(id); return next; })}
              onToggleAll={toggleAllSelection}
              onDownload={() => {}} 
              onRefine={() => {}}
              onDelete={deleteFrame}
              onView={setQuickViewFrame}
              onRestore={viewMode === 'filtered' ? restoreFrame : undefined}
            />
          </div>
        </div>
      </main>

      <AIChat isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} validFrames={frames} />
      <AnimatePresence>
        {quickViewFrame && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex flex-col p-6 items-center justify-center">
            <div className="w-full max-w-6xl flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">Frame View <span className="text-blue-400 font-mono ml-4">{quickViewFrame.timestamp.toFixed(2)}s</span></h3>
              <button onClick={() => setQuickViewFrame(null)} className="p-2 bg-gray-800 rounded-full hover:bg-red-600 text-white"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <img src={quickViewFrame.dataUrl} className="max-w-full max-h-[80vh] object-contain rounded-xl border border-gray-800" />
          </motion.div>
        )}
      </AnimatePresence>
      <div className="fixed bottom-24 right-8"><button onClick={captureManualSnapshot} className="w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-blue-400/20 shadow-2xl transition-transform active:scale-95"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg></button></div>
    </div>
  );
};

