import React from 'react';
import { FixedSizeList as List } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';
import { motion, AnimatePresence } from 'framer-motion';
import { ExtractedFrame } from '../types';

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  selectedIds: Set<string>;
  onToggleSelection: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onRefine: (frame: ExtractedFrame) => void;
  onDelete: (id: string) => void;
  onView: (frame: ExtractedFrame) => void;
  onRestore?: (id: string) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ 
  frames, 
  selectedIds, 
  onToggleSelection, 
  onToggleAll,
  onRefine,
  onDelete,
  onView,
  onRestore
}) => {
  const allSelectedInCurrentView = frames.length > 0 && frames.every(f => selectedIds.has(f.id));

  const getGridConfig = (containerWidth: number) => {
    if (containerWidth < 640) return { columns: 1, gap: 16 };
    if (containerWidth < 1024) return { columns: 2, gap: 20 };
    if (containerWidth < 1440) return { columns: 3, gap: 24 };
    return { columns: 4, gap: 24 };
  };

  const FrameItem = ({ frame, isSelected }: { frame: ExtractedFrame, isSelected: boolean }) => {
    const isManual = frame.id.startsWith('manual');
    const isFiltered = !!frame.filterReason;

    return (
      <motion.div 
        layout
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className={`group relative bg-gray-900 rounded-2xl overflow-hidden border transition-all duration-300 shadow-xl h-full flex flex-col ${
          isSelected ? 'border-blue-500 ring-4 ring-blue-500/10' : 'border-gray-800 hover:border-gray-600'
        }`}
      >
        <div className="aspect-video bg-gray-950 relative overflow-hidden flex-shrink-0">
          <div 
            className="w-full h-full cursor-pointer"
            onClick={() => onToggleSelection(frame.id)}
          >
            <img 
              src={frame.dataUrl} 
              alt={`Timestamp ${frame.timestamp.toFixed(2)}s`}
              className={`w-full h-full object-contain transition-transform duration-700 ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`}
              loading="lazy"
            />
            <AnimatePresence>
              {isSelected && (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="absolute inset-0 bg-blue-600/10 pointer-events-none" 
                />
              )}
            </AnimatePresence>
          </div>

          <div 
            className="absolute top-3 left-3 w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all cursor-pointer z-20 shadow-2xl"
            onClick={(e) => { e.stopPropagation(); onToggleSelection(frame.id); }}
          >
             <div className={`absolute inset-0 rounded-lg transition-all duration-200 ${isSelected ? 'bg-blue-600 border-blue-600' : 'bg-black/60 border-white/20 backdrop-blur-md'}`} />
             <AnimatePresence>
               {isSelected && (
                 <motion.svg 
                    initial={{ scale: 0, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    exit={{ scale: 0, opacity: 0 }}
                    className="w-4 h-4 text-white relative z-10" 
                    fill="none" 
                    stroke="currentColor" 
                    viewBox="0 0 24 24"
                 >
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
                 </motion.svg>
               )}
             </AnimatePresence>
          </div>

          <div className="absolute top-3 right-3 flex gap-2 pointer-events-none z-20">
             {isManual ? (
               <span className="bg-blue-600 text-white text-[8px] px-2 py-0.5 rounded shadow-lg font-black uppercase tracking-wider">Manual</span>
             ) : isFiltered ? (
               <span className="bg-orange-600 text-white text-[8px] px-2 py-0.5 rounded shadow-lg font-black uppercase tracking-wider">
                 {frame.filterReason}
               </span>
             ) : (
               <span className="bg-green-600 text-white text-[8px] px-2 py-0.5 rounded shadow-lg font-black uppercase tracking-wider">Sharp</span>
             )}
          </div>

          <div className="absolute bottom-2 left-2 bg-black/70 backdrop-blur text-[9px] font-bold font-mono py-0.5 px-2 rounded border border-white/10 text-blue-400 pointer-events-none">
            {frame.timestamp.toFixed(2)}s
          </div>
        </div>

        <div className="p-3 flex items-center justify-between bg-gray-900 border-t border-gray-800/80 mt-auto">
          <div className="flex gap-1.5">
            <button 
              onClick={(e) => { e.stopPropagation(); onView(frame); }}
              className="p-1.5 bg-gray-800 hover:bg-blue-600/20 rounded-lg transition-all text-blue-400 border border-gray-700/50"
              title="View Large"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
              </svg>
            </button>
          </div>

          <div className="flex gap-1.5">
            {onRestore && (
              <button 
                onClick={(e) => { e.stopPropagation(); onRestore(frame.id); }}
                className="p-1.5 bg-blue-600 hover:bg-blue-500 rounded-lg transition-all text-white border border-blue-400/30"
                title="Restore to Valid"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                </svg>
              </button>
            )}
            <button 
              onClick={(e) => { e.stopPropagation(); onDelete(frame.id); }}
              className="p-1.5 bg-gray-800 hover:bg-red-600/20 rounded-lg transition-all text-gray-500 hover:text-red-400 border border-gray-700/50"
              title="Delete"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>
        </div>
      </motion.div>
    );
  };

  if (frames.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-20 bg-gray-950/40 rounded-3xl border-2 border-dashed border-gray-800 shadow-inner h-full">
        <div className="bg-gray-900 p-6 rounded-full mb-6 border border-gray-800">
          <svg className="w-12 h-12 text-gray-700" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
          </svg>
        </div>
        <p className="text-gray-400 font-bold text-center max-w-xs uppercase tracking-widest text-xs leading-loose">
          {onRestore ? 'No rejected content to display.' : 'Waiting for video processing...'}
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full gap-4">
      <div className="flex items-center gap-6 py-3 px-6 bg-gray-900 rounded-2xl border border-gray-800 shadow-lg flex-shrink-0">
        <label className="flex items-center gap-4 cursor-pointer group">
          <div className="relative flex items-center">
            <input 
              type="checkbox" 
              checked={allSelectedInCurrentView}
              onChange={(e) => onToggleAll(e.target.checked)}
              className="peer appearance-none w-5 h-5 border-2 border-gray-700 rounded-md checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
            />
            <svg className="absolute w-3 h-3 text-white left-1 pointer-events-none opacity-0 peer-checked:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <span className="text-[10px] font-black text-gray-500 group-hover:text-blue-400 transition-colors uppercase tracking-widest">
            {allSelectedInCurrentView ? 'Deselect All' : 'Select All'}
          </span>
        </label>
        <div className="h-4 w-px bg-gray-800" />
        <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">
          {frames.length} results
        </span>
      </div>

      <div className="flex-1 rounded-3xl overflow-hidden border border-gray-800/50 bg-gray-950 shadow-2xl relative min-h-0">
        <AutoSizer>
          {({ height, width }) => {
            const { columns, gap } = getGridConfig(width);
            const columnWidth = (width - (columns + 1) * gap) / columns;
            const rowHeight = (columnWidth * (9/16)) + 64; 
            const rowCount = Math.ceil(frames.length / columns);

            return (
              <List
                height={height}
                itemCount={rowCount}
                itemSize={rowHeight + gap}
                width={width}
                itemData={{ columns, columnWidth, gap, frames, selectedIds }}
              >
                {({ index, style, data }) => {
                  const { columns, columnWidth, gap, frames, selectedIds } = data;
                  const startIndex = index * columns;
                  const rowFrames = frames.slice(startIndex, startIndex + columns);

                  return (
                    <div style={{ ...style, display: 'flex', paddingLeft: gap, paddingTop: gap }}>
                      {rowFrames.map((frame: ExtractedFrame) => (
                        <div key={frame.id} style={{ width: columnWidth, marginRight: gap, height: rowHeight }}>
                          <FrameItem frame={frame} isSelected={selectedIds.has(frame.id)} />
                        </div>
                      ))}
                    </div>
                  );
                }}
              </List>
            );
          }}
        </AutoSizer>
      </div>
    </div>
  );
};

