import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedFrame, ChatMessage } from '../types';

interface AIChatProps {
  isOpen: boolean;
  onClose: () => void;
  validFrames: ExtractedFrame[];
}

const AIChat: React.FC<AIChatProps> = ({ isOpen, onClose, validFrames }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMessage: ChatMessage = { role: 'user', parts: [{ text: input }] };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      // Fix: Ensure instance is created with proper named parameter.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Provide frame context if available
      const frameContextParts = validFrames.slice(0, 3).map(f => ({
        inlineData: {
          mimeType: "image/png",
          data: f.dataUrl.split(',')[1]
        }
      }));

      const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction: `You are the Anatomi AI Assistant, a world-class video processing and UX Audit expert. 
          You help users analyze video frames extracted from mobile/web apps. 
          Be professional, technical, and concise. 
          If frames are provided, refer to them specifically. 
          Current valid frame count: ${validFrames.length}.`,
        },
        history: messages,
      });

      // Fix: chat.sendMessageStream only accepts the message parameter. 
      // The message parameter should contain the content (array of parts or string).
      const responseStream = await chat.sendMessageStream({ 
        message: [
          ...frameContextParts, 
          { text: input }
        ] 
      });

      let fullText = "";
      setMessages(prev => [...prev, { role: 'model', parts: [{ text: "" }] }]);

      for await (const chunk of responseStream) {
