/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r * 0.299 + g * 0.587 + b * 0.114);
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Detects if a frame is likely a loading screen (skeleton, spinner, or empty/blank state).
 * Heuristic: Skeletons are low saturation, high brightness, and lack high-contrast text pixels.
 */
export function detectLoadingState(canvas: HTMLCanvasElement): boolean {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return false;

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let skeletonGreyCount = 0;
  let blankPixelCount = 0;
  let highContrastTextCount = 0; // Black or very dark pixels indicating text
  let colorPixelCount = 0; // Pixels with significant saturation

  const totalSamples = 400; // Increased sample size for accuracy

  for (let i = 0; i < totalSamples; i++) {
    const idx = Math.floor(Math.random() * (data.length / 4)) * 4;
    const r = data[idx];
    const g = data[idx + 1];
    const b = data[idx + 2];

    const brightness = (r + g + b) / 3;
    const maxVal = Math.max(r, g, b);
    const minVal = Math.min(r, g, b);
    const saturation = maxVal - minVal;

    // 1. Check for significant color (Validation that it's NOT a simple skeleton)
    // Skeletons are usually neutral. Blue buttons, red icons, green status indicate content.
    if (saturation > 25) {
      colorPixelCount++;
    }

    // 2. Check for Text (Dark pixels)
    // Valid screens usually have text (dark grey/black on light background)
    if (brightness < 80) {
      highContrastTextCount++;
    }

    // 3. Check for Skeleton Greys
    // Usually light grey #E0E0E0 (224) to #F5F5F5 (245) with low saturation
    const isLowSat = saturation < 15;
    const isSkeletonRange = brightness > 190 && brightness < 245; 
    if (isLowSat && isSkeletonRange) {
      skeletonGreyCount++;
    }

    // 4. Blank/Empty check (Pure white or Pure black)
    if (brightness > 250 || brightness < 15) {
      blankPixelCount++;
    }
  }

  const skeletonRatio = skeletonGreyCount / totalSamples;
  const textRatio = highContrastTextCount / totalSamples;
  const colorRatio = colorPixelCount / totalSamples;
  const blankRatio = blankPixelCount / totalSamples;

  // RULE 1: Skeleton Screen
  // Significant amount of skeleton grey, very little actual text content, and monochrome.
  if (skeletonRatio > 0.15 && textRatio < 0.05 && colorRatio < 0.1) {
    return true; 
  }

  // RULE 2: Empty/Spinner State
  // Mostly blank (white/black) with very little other content.
  if (blankRatio > 0.90 && textRatio < 0.02) {
    return true;
  }

  return false;
}

/**
 * Detects if the background is dimmed and identifies popups via contrast.
 * High contrast white blocks in the center of a dark background are considered popups.
 */
export function analyzeOverlayState(canvas: HTMLCanvasElement): { isDimmed: boolean, hasPopup: boolean } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { isDimmed: false, hasPopup: false };

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let totalBrightness = 0;
  const step = 40; 
  let sampleCount = 0;

  let edgeBrightness = 0;
  let centerBrightness = 0;
  let edgeSamples = 0;
  let centerSamples = 0;

  let highBrightnessCenterPixels = 0;

  const centerX = width / 2;
  const centerY = height / 2;
  const centerRadiusX = width * 0.35;
  const centerRadiusY = height * 0.3;

  for (let y = 0; y < height; y += step) {
    for (let x = 0; x < width; x += step) {
      const idx = (y * width + x) * 4;
      const r = data[idx];
      const g = data[idx + 1];
      const b = data[idx + 2];
      const brightness = (r + g + b) / 3;

      totalBrightness += brightness;
      sampleCount++;

      const inCenter = Math.abs(x - centerX) < centerRadiusX && Math.abs(y - centerY) < centerRadiusY;
      const atEdge = x < width * 0.1 || x > width * 0.9 || y < height * 0.1 || y > height * 0.9;

      if (inCenter) {
        centerBrightness += brightness;
        centerSamples++;
        if (r > 220 && g > 220 && b > 220) {
          highBrightnessCenterPixels++;
        }
      } else if (atEdge) {
        edgeBrightness += brightness;
        edgeSamples++;
      }
    }
  }

  const avgCenter = centerBrightness / centerSamples;
  const avgEdge = edgeBrightness / edgeSamples;

  const isDimmed = avgEdge < 110; 
  const centerIsHighContrast = avgCenter > avgEdge + 50;
  const centerHasWhiteBox = (highBrightnessCenterPixels / centerSamples) > 0.2;

  const hasPopup = isDimmed && (centerIsHighContrast || centerHasWhiteBox);

  return { isDimmed, hasPopup };
}

/**
 * Sharpness and variance metrics.
 */
export function calculateImageMetrics(canvas: HTMLCanvasElement): { blurScore: number; edgeIntensity: number } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { blurScore: 0, edgeIntensity: 0 };

  const width = canvas.width;
  const height = canvas.height;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  let edgeSum = 0;
  const sampleStep = 32; 
  const sampledGrays: number[] = [];

  for (let i = 0; i < data.length - sampleStep; i += sampleStep) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    sampledGrays.push(gray);
    mean += gray;

    const nextGray = (data[i + 4] * 0.299 + data[i + 5] * 0.587 + data[i + 6] * 0.114);
    edgeSum += Math.abs(gray - nextGray);
  }

  mean /= sampledGrays.length;

  let variance = 0;
  for (const v of sampledGrays) {
    variance += (v - mean) * (v - mean);
  }
  variance /= sampledGrays.length;

  return {
    blurScore: variance, 
    edgeIntensity: edgeSum / sampledGrays.length
  };
}

/**
 * Hamming Distance.
 */
export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, detectLoadingState, analyzeOverlayState } from './services/videoProcessor';
import FrameGallery from './components/FrameGallery';

const FRAME_INTERVAL = 0.5; 
const SIMILARITY_THRESHOLD = 1; 
const TYPING_THRESHOLD = 5; 
const BLUR_THRESHOLD = 120; // Lowered from 180 to catch valid flat UI screens
const TEMPORAL_LOOKAHEAD = 0.15; 
const STABILITY_TOLERANCE = 3; // Increased from 1 to 3 to handle video compression noise

type ViewMode = 'valid' | 'filtered';

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [filteredFrames, setFilteredFrames] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [quickViewFrame, setQuickViewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg'>('png');
  const [exportQuality, setExportQuality] = useState(0.9);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0,
    transitionCount: 0,
    loadingCount: 0,
    typingCount: 0,
    dimmedCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragCounter = useRef(0);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('video/')) {
      alert('Invalid file type.');
      return;
    }
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setQuickViewFrame(null);
    setStats({
      totalFramesAnalyzed: 0,
      duplicateCount: 0,
      blurryCount: 0,
      stableCount: 0,
      transitionCount: 0,
      loadingCount: 0,
      typingCount: 0,
      dimmedCount: 0
    });
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');
    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    dragCounter.current++;
    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    dragCounter.current--;
    if (dragCounter.current === 0) setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    setIsDragging(false);
    dragCounter.current = 0;
    const file = e.dataTransfer.files?.[0];
    if (file) handleFile(file);
  };

  const getFrameMetadata = async (time: number): Promise<{ 
    hash: string, 
    metrics: { blurScore: number, edgeIntensity: number }, 
    isLoading: boolean,
    overlay: { isDimmed: boolean, hasPopup: boolean }
  }> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return { hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } };

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) return resolve({ hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } });

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const isLoading = detectLoadingState(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, isLoading, overlay });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const extracted: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let localStats = { 
      totalFramesAnalyzed: 0, duplicateCount: 0, blurryCount: 0, stableCount: 0, 
      transitionCount: 0, loadingCount: 0, typingCount: 0, dimmedCount: 0 
    };

    let currentCandidate: ExtractedFrame | null = null;

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      const metadata = await getFrameMetadata(time);
      localStats.totalFramesAnalyzed++;
      setProgress(Math.min(100, (time / duration) * 100));

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = hammingDistance(metadata.hash, post.hash);
      const isSharp = metadata.metrics.blurScore > BLUR_THRESHOLD;

      // Allow slight differences to account for video noise/compression, but filter out transitions (large changes)
      const isSettled = postDiff <= STABILITY_TOLERANCE; 

      let filterReason: ExtractedFrame['filterReason'] = undefined;

      if (metadata.isLoading) {
        filterReason = 'loading';
        localStats.loadingCount++;
      } else if (!isSharp) {
        filterReason = 'blurry';
        localStats.blurryCount++;
      } else if (!isSettled) {
        filterReason = 'transition';
        localStats.transitionCount++;
      } else if (metadata.overlay.isDimmed && !metadata.overlay.hasPopup) {
        filterReason = 'dimmed';
        localStats.dimmedCount++;
      } else {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        const newFrame: ExtractedFrame = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: true,
          isUnique: true
        };

        if (!currentCandidate) {
          let isDuplicate = false;
          for (const f of extracted) {
            if (hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD) {
              isDuplicate = true; break;
            }
          }
          if (isDuplicate) {
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else {
            currentCandidate = newFrame;
          }
        } else {
          const distFromCandidate = hammingDistance(metadata.hash, currentCandidate.hash);

          if (distFromCandidate <= SIMILARITY_THRESHOLD) {
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else if (distFromCandidate <= TYPING_THRESHOLD) {
            currentCandidate = newFrame;
          } else {
            extracted.push(currentCandidate);
            localStats.stableCount++;

            let isDuplicate = false;
            for (const f of extracted) {
               if (hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD) {
                 isDuplicate = true; break;
               }
            }

            if (isDuplicate) {
              filterReason = 'duplicate';
              localStats.duplicateCount++;
              currentCandidate = null;
            } else {
              currentCandidate = newFrame;
            }
          }
        }
      }

      if (filterReason) {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        filtered.push({
          id: `filtered-${Math.random().toString(36).substr(2, 9)}`,
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: filterReason !== 'transition',
          isUnique: false,
          filterReason
        });
      }
      setStats({ ...localStats });
    }

    if (currentCandidate) {
      extracted.push(currentCandidate);
      localStats.stableCount++;
    }

    setFrames(extracted);
    setFilteredFrames(filtered);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
    setViewMode('valid');
    setStats({ ...localStats });
  };

  const captureManualSnapshot = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    const time = videoRef.current.currentTime;
    const metadata = await getFrameMetadata(time);
    const dataUrl = canvasRef.current.toDataURL('image/png');
    const manualFrame: ExtractedFrame = {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: time,
      dataUrl,
      blurScore: metadata.metrics.blurScore,
      hash: metadata.hash,
      isStable: true,
      isUnique: true
    };
    setFrames(prev => [...prev, manualFrame].sort((a, b) => a.timestamp - b.timestamp));
    setSelectedIds(prev => new Set([...prev, manualFrame.id]));
  };

  const deleteFrame = (id: string) => {
    setFrames(prev => prev.filter(f => f.id !== id));
    setFilteredFrames(prev => prev.filter(f => f.id !== id));
    setSelectedIds(prev => { const next = new Set(prev); next.delete(id); return next; });
  };

  const restoreFrame = (id: string) => {
    const frame = filteredFrames.find(f => f.id === id);
    if (frame) {
      setFilteredFrames(prev => prev.filter(f => f.id !== id));
      const restored = { ...frame, filterReason: 'manual-restored' as const };
      setFrames(prev => [...prev, restored].sort((a, b) => a.timestamp - b.timestamp));
    }
  };

  const restoreSelectedFrames = () => {
    const toRestore = filteredFrames.filter(f => selectedIds.has(f.id));
    if (toRestore.length === 0) return;
    const restoreIds = new Set(toRestore.map(f => f.id));
    setFilteredFrames(prev => prev.filter(f => !restoreIds.has(f.id)));
    const restored = toRestore.map(f => ({ ...f, filterReason: 'manual-restored' as const }));
    setFrames(prev => [...prev, ...restored].sort((a, b) => a.timestamp - b.timestamp));
    setViewMode('valid');
  };

  const toggleAllSelection = (selected: boolean) => {
    const list = viewMode === 'valid' ? frames : filteredFrames;
    if (selected) setSelectedIds(new Set([...selectedIds, ...list.map(f => f.id)]));
    else {
      const next = new Set(selectedIds);
      list.forEach(f => next.delete(f.id));
      setSelectedIds(next);
    }
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0 || !videoFile) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const all = [...frames, ...filteredFrames];
      const sorted = all.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);
      for (let i = 0; i < sorted.length; i++) {
        const frame = sorted[i];
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`${i + 1}.${exportFormat}`, base64Data, { base64: true });
      }
      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `${videoFile.name.replace(/\.[^/.]+$/, "")}.zip`;
      link.click();
    } finally { setIsDownloading(false); }
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;
  const selectedInActiveCount = activeFrames.filter(f => selectedIds.has(f.id)).length;

  return (
    <div 
      className="max-w-[1600px] mx-auto px-4 py-8 sm:px-6 lg:px-8 min-h-screen flex flex-col relative"
      onDragEnter={handleDragEnter} onDragOver={(e) => e.preventDefault()} onDragLeave={handleDragLeave} onDrop={handleDrop}
    >
      <AnimatePresence>
        {isDragging && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[200] bg-blue-600/20 backdrop-blur-md flex items-center justify-center pointer-events-none">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-gray-900/90 border-4 border-dashed border-blue-500 rounded-[3rem] p-12 flex flex-col items-center gap-6 shadow-2xl">
              <div className="w-24 h-24 bg-blue-600/20 rounded-full flex items-center justify-center">
                <svg className="w-12 h-12 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
              </div>
              <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Drop to Upload</h2>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6 flex-shrink-0">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">Anatomi <span className="text-blue-500">Video Editor</span></h1>
          <p className="text-gray-400 text-xs mt-1 uppercase tracking-widest font-bold">Precision UI/UX Frame Engine</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm shadow-lg">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            <span className="font-bold">Upload</span>
          </label>
          <button disabled={!videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)} onClick={processVideo} className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 text-sm ${!videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED) ? 'bg-gray-800 text-gray-500 cursor-not-allowed opacity-50' : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg'}`}>
            {status === ProcessingStatus.IDLE || status === ProcessingStatus.COMPLETED ? 'Extract Frames' : 'Analyzing...'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0 mb-20">
        <div className="lg:col-span-3 flex flex-col gap-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl flex flex-col">
            <h2 className="text-xs font-black mb-3 uppercase tracking-widest text-gray-500">Source Video</h2>
            <div className="bg-black rounded-xl overflow-hidden border border-gray-800 relative mb-4 shadow-inner">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-auto" controls /> : <div className="aspect-video flex items-center justify-center text-gray-700 text-[10px] font-black uppercase tracking-widest p-6 text-center">No video loaded</div>}
            </div>
            {status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED && (
               <div className="mb-4 p-3 bg-gray-950/50 rounded-xl border border-gray-800/50">
                  <div className="flex justify-between mb-2"><span className="text-[9px] font-black text-blue-400 uppercase">Scanning</span><span className="text-[9px] text-white">{Math.round(progress)}%</span></div>
                  <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden"><motion.div animate={{ width: `${progress}%` }} className="bg-blue-500 h-full shadow-[0_0_8px_rgba(59,130,246,0.5)]" /></div>
               </div>
            )}
            <canvas ref={canvasRef} className="hidden" />
            <div className="grid grid-cols-2 gap-2">
              <button onClick={() => setViewMode('valid')} className={`p-3 rounded-xl border transition-all text-left group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600' : 'bg-gray-800/50 border-gray-700'}`}>
                <div className={`text-lg font-bold ${viewMode === 'valid' ? 'text-blue-400' : 'text-gray-300'}`}>{stats.stableCount}</div>
                <div className="text-[8px] text-gray-500 uppercase font-black">Valid</div>
              </button>
              <button onClick={() => setViewMode('filtered')} className={`p-3 rounded-xl border transition-all text-left group ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600' : 'bg-gray-800/50 border-gray-700'}`}>
                <div className={`text-lg font-bold ${viewMode === 'filtered' ? 'text-orange-400' : 'text-gray-300'}`}>{filteredFrames.length}</div>
                <div className="text-[8px] text-gray-500 uppercase font-black">Filtered</div>
              </button>
            </div>
          </section>
        </div>

        <div className="lg:col-span-9 flex flex-col gap-4 min-h-0">
          <div className="bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex items-center justify-between backdrop-blur-sm">
            <h2 className="text-xl font-bold text-white capitalize">{viewMode} Frames <span className="text-[10px] text-gray-500 ml-2 uppercase tracking-widest">{activeFrames.length} Results</span></h2>
            <div className="flex items-center gap-3">
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-widest transition-all shadow-lg ${selectedIds.size === 0 || isDownloading ? 'bg-gray-800 text-gray-600 cursor-not-allowed' : 'bg-green-600 hover:bg-green-500 text-white'}`}>
                {isDownloading ? 'Processing...' : `Export (${selectedIds.size})`}
              </button>
              {viewMode === 'filtered' && selectedInActiveCount > 0 && <button onClick={restoreSelectedFrames} className="px-4 py-2 rounded-xl bg-blue-600 text-white text-[10px] uppercase font-bold shadow-lg">Restore</button>}
            </div>
          </div>
          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const next = new Set(prev); next.has(id) ? next.delete(id) : next.add(id); return next; })}
              onToggleAll={toggleAllSelection}
              onDelete={deleteFrame}
              onView={setQuickViewFrame}
              onRestore={viewMode === 'filtered' ? restoreFrame : undefined}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {quickViewFrame && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-2xl flex flex-col p-6 items-center justify-center">
            <div className="w-full max-w-6xl flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">Frame View <span className="text-blue-400 font-mono ml-4 text-sm px-2 py-1 bg-blue-400/10 rounded border border-blue-400/20">{quickViewFrame.timestamp.toFixed(2)}s</span></h3>
