            </div>
            <img src={quickViewFrame.dataUrl} className="max-w-full max-h-[85vh] object-contain rounded-2xl border border-gray-800 shadow-2xl" />
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed bottom-24 right-8 z-[100]">
        <button onClick={captureManualSnapshot} className="w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-blue-400/20 shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all active:scale-90 active:shadow-none">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
        </button>
      </div>
    </div>
  );
};

