import React, { useState, useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ExtractedFrame } from '../types';

interface RedactionViewerProps {
  frame: ExtractedFrame;
  onClose: () => void;
  onSave: (id: string, rects: {x: number, y: number, w: number, h: number}[]) => void;
}

const RedactionViewer: React.FC<RedactionViewerProps> = ({ frame, onClose, onSave }) => {
  const [rects, setRects] = useState<{x: number, y: number, w: number, h: number}[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentRect, setCurrentRect] = useState<{x: number, y: number, w: number, h: number} | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  const getRelativeCoords = (e: React.MouseEvent | React.TouchEvent) => {
    if (!imgRef.current) return { x: 0, y: 0 };
    const rect = imgRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    // Calculate normalized coordinates (0 to naturalWidth)
    const x = (clientX - rect.left) * (imgRef.current.naturalWidth / rect.width);
    const y = (clientY - rect.top) * (imgRef.current.naturalHeight / rect.height);
    return { x, y };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getRelativeCoords(e);
    setIsDrawing(true);
    setCurrentRect({ ...coords, w: 0, h: 0 });
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !currentRect) return;
    const coords = getRelativeCoords(e);
    setCurrentRect({
      ...currentRect,
      w: coords.x - currentRect.x,
      h: coords.y - currentRect.y
    });
  };

  const handleEnd = () => {
    if (currentRect && Math.abs(currentRect.w) > 10 && Math.abs(currentRect.h) > 10) {
      // Normalize rect (handle negative w/h)
      const normalized = {
        x: currentRect.w < 0 ? currentRect.x + currentRect.w : currentRect.x,
        y: currentRect.h < 0 ? currentRect.y + currentRect.h : currentRect.y,
        w: Math.abs(currentRect.w),
        h: Math.abs(currentRect.h)
      };
      setRects([...rects, normalized]);
    }
    setIsDrawing(false);
    setCurrentRect(null);
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-xl flex flex-col p-6 overflow-hidden">
      <div className="flex justify-between items-center mb-4">
        <div>
          <h3 className="text-xl font-bold text-white">PII Redactor</h3>
          <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">Draw boxes over sensitive data to blur</p>
        </div>
        <div className="flex gap-4">
          <button onClick={() => setRects([])} className="px-4 py-2 rounded-xl bg-gray-800 text-gray-400 hover:text-white text-xs font-bold transition-all">Clear All</button>
          <button onClick={() => onSave(frame.id, rects)} className="px-4 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold shadow-lg transition-all">Save Redacted Frame</button>
          <button onClick={onClose} className="p-2 bg-gray-800 rounded-full hover:bg-red-600 text-white transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
      </div>

      <div className="flex-1 flex items-center justify-center relative overflow-hidden bg-gray-900 rounded-3xl border border-gray-800 cursor-crosshair group"
