/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r * 0.299 + g * 0.587 + b * 0.114);
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Enhanced Skeleton Detection matching the provided reference.
 * It detects "Placeholder UI" by looking for specific grey-tone clusters (circles/bars)
 * against a light background, and lack of real text contrast in the content area.
 */
export function detectLoadingState(canvas: HTMLCanvasElement): boolean {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return false;

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let skeletonPixelCount = 0;
  let textPixelCount = 0;
  let backgroundPixelCount = 0;

  const samples = 600; 
  const greyRange = { min: 215, max: 240 }; // Standard Skeleton Grey (#D1 to #F0)

  for (let i = 0; i < samples; i++) {
    const x = Math.floor(Math.random() * width);
    const y = Math.floor(Math.random() * height);
    const idx = (y * width + x) * 4;

    const r = data[idx];
    const g = data[idx + 1];
    const b = data[idx + 2];
    const brightness = (r + g + b) / 3;
    const isNeutral = Math.abs(r - g) < 8 && Math.abs(g - b) < 8;

    // 1. Detect Skeleton placeholders (The grey circles and bars)
    if (isNeutral && brightness >= greyRange.min && brightness <= greyRange.max) {
      skeletonPixelCount++;
    }

    // 2. Detect actual text (High contrast dark pixels)
    if (brightness < 80) {
      textPixelCount++;
    }

    // 3. Detect card/background (Usually near white)
    if (brightness > 245) {
      backgroundPixelCount++;
    }
  }

  const skeletonRatio = skeletonPixelCount / samples;
  const textRatio = textPixelCount / samples;
  const bgRatio = backgroundPixelCount / samples;

  // Pattern Logic:
  // Skeleton screens have high 'Skeleton Grey' count but very low 'Actual Text' count.
  // Real screens with lists have much higher textRatio (letters/icons) and varied colors.
  const isSkeletonBody = skeletonRatio > 0.12 && textRatio < 0.04;

  // Also check if the screen is mostly empty (white) but has no content
  const isEmptyState = bgRatio > 0.85 && textRatio < 0.01;

  return isSkeletonBody || isEmptyState;
}

/**
 * Detects if the background is dimmed and identifies popups via contrast.
 */
export function analyzeOverlayState(canvas: HTMLCanvasElement): { isDimmed: boolean, hasPopup: boolean } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { isDimmed: false, hasPopup: false };

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let edgeBrightness = 0;
  let centerBrightness = 0;
  let edgeSamples = 0;
  let centerSamples = 0;

  const step = 50;
  const centerX = width / 2;
  const centerY = height / 2;
  const cRx = width * 0.3;
  const cRy = height * 0.25;

  for (let y = 0; y < height; y += step) {
    for (let x = 0; x < width; x += step) {
      const idx = (y * width + x) * 4;
      const bri = (data[idx] + data[idx+1] + data[idx+2]) / 3;

      const inCenter = Math.abs(x - centerX) < cRx && Math.abs(y - centerY) < cRy;
      const atEdge = x < width * 0.1 || x > width * 0.9 || y < height * 0.1 || y > height * 0.9;

      if (inCenter) {
        centerBrightness += bri;
        centerSamples++;
      } else if (atEdge) {
        edgeBrightness += bri;
        edgeSamples++;
      }
    }
  }

  const avgEdge = edgeBrightness / edgeSamples;
  const avgCenter = centerBrightness / centerSamples;

  const isDimmed = avgEdge < 100;
  const hasPopup = isDimmed && avgCenter > avgEdge + 60;

  return { isDimmed, hasPopup };
}

/**
 * Sharpness and variance metrics.
 */
export function calculateImageMetrics(canvas: HTMLCanvasElement): { blurScore: number; edgeIntensity: number } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { blurScore: 0, edgeIntensity: 0 };

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  let edgeSum = 0;
  const sampleStep = 32; 
  let count = 0;

  for (let i = 0; i < data.length - 4; i += sampleStep * 4) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    mean += gray;
    count++;
    const nextGray = (data[i + 4] * 0.299 + data[i + 5] * 0.587 + data[i + 6] * 0.114);
    edgeSum += Math.abs(gray - nextGray);
  }

  mean /= count;
  let variance = 0;
  for (let i = 0; i < data.length - 4; i += sampleStep * 4) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    variance += Math.pow(gray - mean, 2);
  }
  variance /= count;

  return { blurScore: variance, edgeIntensity: edgeSum / count };
}

export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

/**
 * Bakes a list of redaction rectangles onto a dataUrl and returns the new dataUrl.
 */
export function applyRedaction(dataUrl: string, rects: {x: number, y: number, w: number, h: number}[]): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d')!;
      ctx.drawImage(img, 0, 0);
      rects.forEach(r => {
        ctx.save();
        ctx.beginPath();
        ctx.rect(r.x, r.y, r.w, r.h);
        ctx.clip();
        ctx.filter = 'blur(25px)';
        ctx.drawImage(img, 0, 0);
        ctx.fillStyle = 'rgba(0,0,0,0.15)';
        ctx.fillRect(r.x, r.y, r.w, r.h);
        ctx.restore();
      });
      resolve(canvas.toDataURL('image/png'));
    };
    img.src = dataUrl;
  });
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, detectLoadingState, analyzeOverlayState, applyRedaction } from './services/videoProcessor';
import FrameGallery from './components/FrameGallery';
import RedactionViewer from './components/RedactionViewer';

const FRAME_INTERVAL = 0.5; 
const SIMILARITY_THRESHOLD = 1; 
const TYPING_THRESHOLD = 5; 
const BLUR_THRESHOLD = 160; // Slightly lower to catch more subtle but valid sharp screens
const TEMPORAL_LOOKAHEAD = 0.15; 

type ViewMode = 'valid' | 'filtered';

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [filteredFrames, setFilteredFrames] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [quickViewFrame, setQuickViewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0,
    transitionCount: 0,
    loadingCount: 0,
    typingCount: 0,
    dimmedCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('video/')) return;
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setQuickViewFrame(null);
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');
    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const getFrameMetadata = async (time: number): Promise<{ 
    hash: string, metrics: { blurScore: number, edgeIntensity: number }, isLoading: boolean, overlay: { isDimmed: boolean, hasPopup: boolean }
  }> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return { hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } };

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) return;
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve({
          hash: await calculateAverageHash(canvas),
          metrics: calculateImageMetrics(canvas),
          isLoading: detectLoadingState(canvas),
          overlay: analyzeOverlayState(canvas)
        });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setFilteredFrames([]);
    setProgress(0);

    const duration = videoRef.current.duration;
    const extracted: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let localStats = { ...stats, totalFramesAnalyzed: 0 };
    let currentCandidate: ExtractedFrame | null = null;

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      // Deliberate throttle for visual scanning effect and UI responsiveness
      await new Promise(r => setTimeout(r, 65)); 

      const metadata = await getFrameMetadata(time);
      localStats.totalFramesAnalyzed++;
      setProgress((time / duration) * 100);

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const isSharp = metadata.metrics.blurScore > BLUR_THRESHOLD;
      const isSettled = hammingDistance(metadata.hash, post.hash) <= 1; 

      let filterReason: ExtractedFrame['filterReason'] = undefined;
      if (metadata.isLoading) filterReason = 'loading';
      else if (!isSharp) filterReason = 'blurry';
      else if (!isSettled) filterReason = 'transition';
      else if (metadata.overlay.isDimmed && !metadata.overlay.hasPopup) filterReason = 'dimmed';
      else {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        const newFrame: ExtractedFrame = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: true,
          isUnique: true
        };

        if (!currentCandidate) {
          const isDup = extracted.some(f => hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD);
          if (isDup) filterReason = 'duplicate';
          else currentCandidate = newFrame;
        } else {
          const dist = hammingDistance(metadata.hash, currentCandidate.hash);
          if (dist <= SIMILARITY_THRESHOLD) filterReason = 'duplicate';
          else if (dist <= TYPING_THRESHOLD) currentCandidate = newFrame;
          else {
            extracted.push(currentCandidate);
            currentCandidate = newFrame;
          }
        }
      }

      if (filterReason) {
        filtered.push({
          id: `filtered-${Math.random().toString(36).substr(2, 9)}`,
          timestamp: time,
          dataUrl: canvasRef.current!.toDataURL('image/png'),
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: filterReason !== 'transition',
          isUnique: false,
          filterReason
        });
      }

      if (localStats.totalFramesAnalyzed % 4 === 0) {
        setFrames([...extracted]);
        setFilteredFrames([...filtered]);
      }
    }

    if (currentCandidate) extracted.push(currentCandidate);
    setFrames(extracted);
    setFilteredFrames(filtered);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const restoreSelected = () => {
    const toRestore = filteredFrames.filter(f => selectedIds.has(f.id));
    if (!toRestore.length) return;

    const restoreIds = new Set(toRestore.map(f => f.id));
    setFilteredFrames(prev => prev.filter(f => !restoreIds.has(f.id)));

    const restored = toRestore.map(f => ({ ...f, filterReason: 'manual-restored' as any }));
    setFrames(prev => [...prev, ...restored].sort((a, b) => a.timestamp - b.timestamp));

    const nextSelected = new Set(selectedIds);
    setSelectedIds(nextSelected);
    setViewMode('valid');
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const all = [...frames, ...filteredFrames];
      const selected = all.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);
      selected.forEach((f, i) => {
        zip.file(`${i + 1}.png`, f.dataUrl.split(',')[1], { base64: true });
      });
      const blob = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `Screenshots_${new Date().getTime()}.zip`;
      link.click();
    } finally { setIsDownloading(false); }
  };

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-8 min-h-screen flex flex-col bg-gray-950">
      <header className="mb-8 flex flex-col md:flex-row items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black tracking-tighter text-white">ANATOMI <span className="text-blue-500">PRO</span></h1>
          <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.3em]">Advanced Video Analysis & PII Shield</p>
        </div>
