            {status === ProcessingStatus.EXTRACTING ? 'Analyzing Pixels...' : 'Run Extraction'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 min-h-0">
        <aside className="lg:col-span-3 space-y-6">
          <section className="bg-gray-900/40 rounded-[2rem] border border-gray-800 p-6 backdrop-blur-xl">
            <h2 className="text-[10px] font-black mb-4 uppercase tracking-[0.2em] text-gray-500">Source Deck</h2>
            <div className="bg-black rounded-2xl overflow-hidden border border-gray-800 aspect-video relative mb-6 shadow-2xl">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-full object-contain" muted /> : <div className="w-full h-full flex items-center justify-center text-gray-800 text-[8px] font-black uppercase">No Content</div>}
              {status === ProcessingStatus.EXTRACTING && (
                <div className="absolute inset-0 bg-blue-600/5 flex items-center justify-center">
                  <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full" />
                </div>
              )}
            </div>

            {status === ProcessingStatus.EXTRACTING && (
              <div className="mb-6">
                <div className="flex justify-between text-[10px] font-black text-blue-400 uppercase mb-2"><span>Scanning...</span><span>{Math.round(progress)}%</span></div>
                <div className="h-1 bg-gray-800 rounded-full overflow-hidden"><motion.div animate={{ width: `${progress}%` }} className="h-full bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.6)]" /></div>
              </div>
            )}

            <div className="space-y-2">
              <button onClick={() => setViewMode('valid')} className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600' : 'bg-gray-800/40 border-gray-700'}`}>
                <span className="text-[10px] font-black uppercase text-gray-400">Valid</span>
                <span className="text-lg font-bold text-white">{frames.length}</span>
              </button>
              <button onClick={() => setViewMode('filtered')} className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600' : 'bg-gray-800/40 border-gray-700'}`}>
                <span className="text-[10px] font-black uppercase text-gray-400">Filtered</span>
                <span className="text-lg font-bold text-white">{filteredFrames.length}</span>
              </button>
            </div>
          </section>
        </aside>

        <section className="lg:col-span-9 flex flex-col gap-6 min-h-0">
          <div className="flex items-center justify-between bg-gray-900/20 p-6 rounded-[2rem] border border-gray-800/50 backdrop-blur-sm">
            <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{viewMode} <span className="text-gray-600 text-sm ml-2">Screens</span></h2>
            <div className="flex gap-4">
              {viewMode === 'filtered' && selectedIds.size > 0 && (
                <button onClick={restoreSelected} className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shadow-xl">Move to Valid</button>
              )}
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedIds.size === 0 ? 'bg-gray-800 text-gray-600' : 'bg-green-600 text-white hover:bg-green-500 shadow-xl'}`}>
                {isDownloading ? 'Zipping...' : `Export (${selectedIds.size})`}
              </button>
            </div>
          </div>

          <div className="flex-1 min-h-0">
            <FrameGallery 
              frames={viewMode === 'valid' ? frames : filteredFrames} 
              selectedIds={selectedIds}
              onToggleSelection={id => setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; })}
              onToggleAll={sel => setSelectedIds(sel ? new Set((viewMode === 'valid' ? frames : filteredFrames).map(f => f.id)) : new Set())}
              onDelete={id => { setFrames(f => f.filter(x => x.id !== id)); setFilteredFrames(f => f.filter(x => x.id !== id)); }}
              onView={setQuickViewFrame}
              onRestore={viewMode === 'filtered' ? (id) => {
                const f = filteredFrames.find(x => x.id === id);
                if(f) { setFilteredFrames(prev => prev.filter(x => x.id !== id)); setFrames(prev => [...prev, {...f, filterReason: 'manual-restored' as any}].sort((a,b)=>a.timestamp-b.timestamp)); }
              } : undefined}
            />
          </div>
        </section>
      </main>

      <canvas ref={canvasRef} className="hidden" />
      <AnimatePresence>
        {quickViewFrame && (
          <RedactionViewer 
            frame={quickViewFrame} 
            onClose={() => setQuickViewFrame(null)} 
            onSave={async (id, rects) => {
              const f = frames.find(x => x.id === id);
              if (f) {
                const url = await applyRedaction(f.dataUrl, rects);
                setFrames(prev => prev.map(x => x.id === id ? { ...x, dataUrl: url, redacted: true } : x));
                setQuickViewFrame(null);
              }
            }} 
          />
        )}
      </AnimatePresence>
    </div>
  );
};

