          <img src={frame.dataUrl} alt="Screen" className={`w-full h-full object-contain transition-transform duration-700 ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`} loading="lazy" />

          <div className="absolute top-3 left-3 w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all bg-black/40 border-white/20 backdrop-blur-md">
             {isSelected && <div className="w-2.5 h-2.5 bg-blue-500 rounded-sm" />}
          </div>

          <div className="absolute top-3 right-3 flex flex-col gap-1 items-end">
             {isFiltered ? (
               <span className="bg-orange-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">{frame.filterReason}</span>
             ) : (
               <span className="bg-green-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">Valid</span>
             )}
          </div>

          <div className="absolute bottom-2 left-2 bg-black/70 backdrop-blur text-[9px] font-bold font-mono py-0.5 px-2 rounded border border-white/10 text-blue-400">
            {frame.timestamp.toFixed(2)}s
