import { GoogleGenAI, Type } from "@google/genai";

export interface BoundingBox {
  ymin: number;
  xmin: number;
  ymax: number;
  xmax: number;
  label: string;
}

/**
 * Uses Gemini 3 Vision to detect PII in a frame.
 * Returns normalized coordinates [0-1000].
 */
export const detectPII = async (dataUrl: string): Promise<BoundingBox[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64Data = dataUrl.split(',')[1];

  const prompt = `
    Analyze this application screenshot and identify all Personal Identifying Information (PII). 
    This is critical for privacy compliance. Detect and return bounding boxes for:
    - Faces
    - Identity Documents (IDs, Passports, Licenses)
    - Financial Info (IBAN, Credit Card numbers, Bank Account numbers)
    - Full Names (in both Arabic and English scripts)
    - Residential Addresses
    - Dates of Birth (DOB)
    - Phone numbers or Email addresses

    Return the result as a JSON array of objects, each with ymin, xmin, ymax, xmax (scale 0-1000) and a label.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/png", data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              ymin: { type: Type.NUMBER },
              xmin: { type: Type.NUMBER },
              ymax: { type: Type.NUMBER },
              xmax: { type: Type.NUMBER },
              label: { type: Type.STRING }
            },
            required: ["ymin", "xmin", "ymax", "xmax", "label"]
          }
        }
      }
    });

    const jsonStr = response.text;
    return JSON.parse(jsonStr) as BoundingBox[];
  } catch (error) {
    console.error("Gemini PII Detection Error:", error);
    return [];
  }
};

import { ExtractedFrame } from '../types';

/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r * 0.299 + g * 0.587 + b * 0.114);
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Advanced Skeleton Detection.
 * Specifically targets placeholder patterns: Repeating grey bars and circles on light cards.
 */
export function detectLoadingState(canvas: HTMLCanvasElement): boolean {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return false;

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let skeletonPixelCount = 0;
  let textPixelCount = 0;
  let backgroundPixelCount = 0;

  const samples = 1000; 
  const greyRange = { min: 200, max: 242 }; 

  for (let i = 0; i < samples; i++) {
    const x = Math.floor(Math.random() * width);
    const y = Math.floor(Math.random() * height);
    const idx = (y * width + x) * 4;

    const r = data[idx];
    const g = data[idx + 1];
    const b = data[idx + 2];
    const brightness = (r + g + b) / 3;
    const isNeutral = Math.abs(r - g) < 12 && Math.abs(g - b) < 12;

    if (isNeutral && brightness >= greyRange.min && brightness <= greyRange.max) {
      skeletonPixelCount++;
    }
    if (brightness < 60) {
      textPixelCount++;
    }
    if (brightness > 248) {
      backgroundPixelCount++;
    }
  }

  const skeletonRatio = skeletonPixelCount / samples;
  const textRatio = textPixelCount / samples;
  const bgRatio = backgroundPixelCount / samples;

  // Very specific for loading states: moderate grey placeholder noise with near-zero real text contrast
  const isSkeletonBody = skeletonRatio > 0.08 && textRatio < 0.03;
  const isEmptyState = bgRatio > 0.94 && textRatio < 0.01;

  return isSkeletonBody || isEmptyState;
}

export function analyzeOverlayState(canvas: HTMLCanvasElement): { isDimmed: boolean, hasPopup: boolean } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { isDimmed: false, hasPopup: false };

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let edgeBrightness = 0;
  let centerBrightness = 0;
  let edgeSamples = 0;
  let centerSamples = 0;

  const step = 40;
  const centerX = width / 2;
  const centerY = height / 2;
  const cRx = width * 0.35;
  const cRy = height * 0.3;

  for (let y = 0; y < height; y += step) {
    for (let x = 0; x < width; x += step) {
      const idx = (y * width + x) * 4;
      const r = data[idx];
      const bri = (r + data[idx+1] + data[idx+2]) / 3;

      const inCenter = Math.abs(x - centerX) < cRx && Math.abs(y - centerY) < cRy;
      const atEdge = x < width * 0.1 || x > width * 0.9 || y < height * 0.1 || y > height * 0.9;

      if (inCenter) {
        centerBrightness += bri;
        centerSamples++;
      } else if (atEdge) {
        edgeBrightness += bri;
        edgeSamples++;
      }
    }
  }

  const isDimmed = (edgeBrightness / edgeSamples) < 100;
  const hasPopup = isDimmed && ((centerBrightness / centerSamples) > (edgeBrightness / edgeSamples) + 50);

  return { isDimmed, hasPopup };
}

export function calculateImageMetrics(canvas: HTMLCanvasElement): { blurScore: number; edgeIntensity: number } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { blurScore: 0, edgeIntensity: 0 };

  const { width, height } = canvas;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  let edgeSum = 0;
  const sampleStep = 32; 
  let count = 0;

  for (let i = 0; i < data.length - 4; i += sampleStep * 4) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    mean += gray;
    count++;
    const nextGray = (data[i + 4] * 0.299 + data[i + 5] * 0.587 + data[i + 6] * 0.114);
    edgeSum += Math.abs(gray - nextGray);
  }

  mean /= count;
  let variance = 0;
  for (let i = 0; i < data.length - 4; i += sampleStep * 4) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    variance += Math.pow(gray - mean, 2);
  }
  variance /= count;

  return { blurScore: variance, edgeIntensity: edgeSum / count };
}

export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

export function applyRedaction(dataUrl: string, rects: {x: number, y: number, w: number, h: number}[]): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d')!;
      ctx.drawImage(img, 0, 0);

      rects.forEach(r => {
        ctx.save();
        ctx.beginPath();
        ctx.rect(r.x, r.y, r.w, r.h);
        ctx.clip();
        ctx.filter = 'blur(40px)';
        ctx.drawImage(img, 0, 0);
        ctx.fillStyle = 'rgba(0,0,0,0.2)';
        ctx.fillRect(r.x, r.y, r.w, r.h);
        ctx.restore();
      });

      resolve(canvas.toDataURL('image/png'));
    };
    img.src = dataUrl;
  });
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, detectLoadingState, analyzeOverlayState, applyRedaction } from './services/videoProcessor';
import { detectPII, BoundingBox } from './services/geminiService';
import FrameGallery from './components/FrameGallery';
import RedactionViewer from './components/RedactionViewer';

const FRAME_INTERVAL = 0.5; 
const SIMILARITY_THRESHOLD = 1; 
const TYPING_THRESHOLD = 5; 
const BLUR_THRESHOLD = 180; 
const TEMPORAL_LOOKAHEAD = 0.15; 

type ViewMode = 'valid' | 'filtered';

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [filteredFrames, setFilteredFrames] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [previewFrame, setPreviewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0,
    transitionCount: 0,
    loadingCount: 0,
    typingCount: 0,
    dimmedCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('video/')) {
      alert('Invalid file type.');
      return;
    }
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setPreviewFrame(null);
    setStats({
      totalFramesAnalyzed: 0, duplicateCount: 0, blurryCount: 0, stableCount: 0,
      transitionCount: 0, loadingCount: 0, typingCount: 0, dimmedCount: 0
    });
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');
    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const getFrameMetadata = async (time: number): Promise<{ 
    hash: string, 
    metrics: { blurScore: number, edgeIntensity: number }, 
    isLoading: boolean,
    overlay: { isDimmed: boolean, hasPopup: boolean }
  }> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return { hash: '', metrics: { blurScore: 0, edgeIntensity: 0 }, isLoading: false, overlay: { isDimmed: false, hasPopup: false } };

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) return;

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const isLoading = detectLoadingState(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, isLoading, overlay });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const extracted: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let localStats = { 
      totalFramesAnalyzed: 0, duplicateCount: 0, blurryCount: 0, stableCount: 0, 
      transitionCount: 0, loadingCount: 0, typingCount: 0, dimmedCount: 0 
    };

    let currentCandidate: ExtractedFrame | null = null;

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await new Promise(r => setTimeout(r, 65)); 

      const metadata = await getFrameMetadata(time);
      localStats.totalFramesAnalyzed++;
      setProgress(Math.min(100, (time / duration) * 100));

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = hammingDistance(metadata.hash, post.hash);
      const isSharp = metadata.metrics.blurScore > BLUR_THRESHOLD;
      const isSettled = postDiff <= 1; 

      let filterReason: ExtractedFrame['filterReason'] = undefined;

      // Reinforced logic: Loading screens are strictly filtered out of valid list
      if (metadata.isLoading) {
        filterReason = 'loading';
        localStats.loadingCount++;
      } else if (!isSharp) {
        filterReason = 'blurry';
        localStats.blurryCount++;
      } else if (!isSettled) {
        filterReason = 'transition';
        localStats.transitionCount++;
      } else if (metadata.overlay.isDimmed && !metadata.overlay.hasPopup) {
        filterReason = 'dimmed';
        localStats.dimmedCount++;
      } else {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        const newFrame: ExtractedFrame = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: true,
          isUnique: true
        };

        if (!currentCandidate) {
          let isDuplicate = false;
          for (const f of extracted) {
            if (hammingDistance(metadata.hash, f.hash) <= SIMILARITY_THRESHOLD) {
              isDuplicate = true; break;
            }
          }
          if (isDuplicate) {
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else {
            currentCandidate = newFrame;
          }
        } else {
          const distFromCandidate = hammingDistance(metadata.hash, currentCandidate.hash);
          if (distFromCandidate <= SIMILARITY_THRESHOLD) {
            filterReason = 'duplicate';
            localStats.duplicateCount++;
          } else if (distFromCandidate <= TYPING_THRESHOLD) {
            currentCandidate = newFrame;
          } else {
            extracted.push(currentCandidate);
            localStats.stableCount++;
            currentCandidate = newFrame;
          }
        }
      }

      if (filterReason) {
        const dataUrl = canvasRef.current!.toDataURL('image/png');
        filtered.push({
          id: `filtered-${Math.random().toString(36).substr(2, 9)}`,
          timestamp: time,
          dataUrl,
          blurScore: metadata.metrics.blurScore,
          hash: metadata.hash,
          isStable: filterReason !== 'transition',
          isUnique: false,
          filterReason
        });
      }

      setStats({ ...localStats });
      if (localStats.totalFramesAnalyzed % 5 === 0) {
        setFrames([...extracted]);
        setFilteredFrames([...filtered]);
      }
    }

    if (currentCandidate) {
      extracted.push(currentCandidate);
      localStats.stableCount++;
    }

    setFrames(extracted);
    setFilteredFrames(filtered);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
    setStats({ ...localStats });
  };

  const autoBlurSelected = async () => {
    if (selectedIds.size === 0) return;
    setStatus(ProcessingStatus.AUTO_BLURRING);

    const framesToBlur = [...frames, ...filteredFrames].filter(f => selectedIds.has(f.id));

    for (const frame of framesToBlur) {
      const boxes = await detectPII(frame.dataUrl);
      if (boxes.length > 0) {
        // We need to convert normalized AI coords to pixel coords
        // Gemini returns [ymin, xmin, ymax, xmax] in 0-1000 scale
        const img = new Image();
        await new Promise((resolve) => {
          img.onload = resolve;
          img.src = frame.dataUrl;
        });

        const pixelRects = boxes.map(box => ({
          x: (box.xmin / 1000) * img.naturalWidth,
          y: (box.ymin / 1000) * img.naturalHeight,
          w: ((box.xmax - box.xmin) / 1000) * img.naturalWidth,
          h: ((box.ymax - box.ymin) / 1000) * img.naturalHeight
        }));

        const redactedUrl = await applyRedaction(frame.dataUrl, pixelRects);
        const updateFn = (f: ExtractedFrame) => f.id === frame.id ? { ...f, dataUrl: redactedUrl, redacted: true } : f;
        setFrames(prev => prev.map(updateFn));
        setFilteredFrames(prev => prev.map(updateFn));
      }
    }

    setStatus(ProcessingStatus.COMPLETED);
  };

  const moveFilteredToValid = useCallback((id: string) => {
    const frame = filteredFrames.find(f => f.id === id);
    if (!frame) return;
    setFilteredFrames(prev => prev.filter(f => f.id !== id));
    setFrames(prev => [...prev, { ...frame, filterReason: 'manual-restored' }].sort((a, b) => a.timestamp - b.timestamp));
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.add(id);
      return next;
    });
  }, [filteredFrames]);

  const moveSelectedFilteredToValid = useCallback(() => {
    const toRestore = filteredFrames.filter(f => selectedIds.has(f.id));
    if (toRestore.length === 0) return;

    const restoreIds = new Set(toRestore.map(f => f.id));
    setFilteredFrames(prev => prev.filter(f => !restoreIds.has(f.id)));
    setFrames(prev => [
      ...prev, 
      ...toRestore.map(f => ({ ...f, filterReason: 'manual-restored' as any }))
    ].sort((a, b) => a.timestamp - b.timestamp));

    setViewMode('valid');
  }, [filteredFrames, selectedIds]);

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const allFrames = [...frames, ...filteredFrames];
      const items = allFrames.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);

      items.forEach((frame, idx) => {
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`${idx + 1}_${frame.timestamp.toFixed(2)}s.png`, base64Data, { base64: true });
      });

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `anatomi_screens_${new Date().getTime()}.zip`;
      link.click();
    } catch (e) {
      console.error(e);
    } finally {
      setIsDownloading(false);
    }
  };

  const captureManualSnapshot = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/png');
    const metrics = calculateImageMetrics(canvas);
    const hash = await calculateAverageHash(canvas);

    const newFrame: ExtractedFrame = {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: video.currentTime,
      dataUrl,
      blurScore: metrics.blurScore,
      hash,
      isStable: true,
      isUnique: true,
      filterReason: 'manual-restored'
    };

    setFrames(prev => [...prev, newFrame].sort((a, b) => a.timestamp - b.timestamp));
    setStatus(ProcessingStatus.COMPLETED);
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-8 min-h-screen flex flex-col relative bg-gray-950">
      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">Anatomi <span className="text-blue-500">Video Editor</span></h1>
          <p className="text-gray-400 text-xs mt-1 uppercase tracking-widest font-bold">Automatic PII Shield & UI Audit</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm shadow-lg">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            <span className="font-bold">Upload Video</span>
          </label>
          <button 
            disabled={!videoFile || status === ProcessingStatus.EXTRACTING} 
            onClick={processVideo} 
            className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 text-sm ${status === ProcessingStatus.EXTRACTING ? 'bg-blue-600/50 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg'}`}
          >
            {status === ProcessingStatus.EXTRACTING ? 'Scanning...' : 'Extract Screens'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0">
        <div className="lg:col-span-3">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl">
            <h2 className="text-xs font-black mb-3 uppercase tracking-widest text-gray-500">Live Preview</h2>
            <div className="bg-black rounded-xl overflow-hidden border border-gray-800 relative mb-4">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-auto" controls /> : <div className="aspect-video flex items-center justify-center text-gray-700 text-[10px] font-black uppercase tracking-widest p-6 text-center">No video loaded</div>}
              {status === ProcessingStatus.EXTRACTING && (
                <div className="absolute inset-0 bg-blue-600/10 pointer-events-none flex items-center justify-center">
                  <motion.div animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.6, 0.3] }} transition={{ repeat: Infinity, duration: 1.5 }} className="w-20 h-20 rounded-full border-2 border-blue-500/50" />
                </div>
              )}
            </div>
            {status === ProcessingStatus.EXTRACTING && (
              <div className="mb-4">
                <div className="flex justify-between text-[10px] font-bold text-blue-400 uppercase mb-1">
                  <span>Scanning Video</span>
                  <span>{Math.round(progress)}%</span>
                </div>
                <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                  <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="bg-blue-500 h-full shadow-[0_0_8px_rgba(59,130,246,0.5)]" />
                </div>
              </div>
            )}
            <canvas ref={canvasRef} className="hidden" />
            <div className="grid grid-cols-2 gap-2">
              <button onClick={() => setViewMode('valid')} className={`p-3 rounded-xl border transition-all text-left ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600' : 'bg-gray-800/50 border-gray-700'}`}>
                <div className="text-lg font-bold text-white">{frames.length}</div>
                <div className="text-[8px] text-gray-500 uppercase font-black">Valid Screens</div>
              </button>
              <button onClick={() => setViewMode('filtered')} className={`p-3 rounded-xl border transition-all text-left ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600' : 'bg-gray-800/50 border-gray-700'}`}>
                <div className="text-lg font-bold text-white">{filteredFrames.length}</div>
                <div className="text-[8px] text-gray-500 uppercase font-black">Filtered</div>
              </button>
            </div>
          </section>
        </div>

        <div className="lg:col-span-9 flex flex-col gap-4">
          <div className="bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex items-center justify-between backdrop-blur-sm">
            <h2 className="text-xl font-bold text-white capitalize">{viewMode} Results</h2>
            <div className="flex items-center gap-3">
              {selectedIds.size > 0 && (
                <button 
                  onClick={autoBlurSelected} 
                  disabled={status === ProcessingStatus.AUTO_BLURRING}
                  className={`px-4 py-2 rounded-xl text-white text-[10px] uppercase font-bold shadow-lg transition-all ${status === ProcessingStatus.AUTO_BLURRING ? 'bg-purple-600/50' : 'bg-purple-600 hover:bg-purple-500'}`}
                >
                  {status === ProcessingStatus.AUTO_BLURRING ? 'Shielding PII...' : 'Auto-Blur PII'}
                </button>
              )}
              {viewMode === 'filtered' && selectedIds.size > 0 && (
                <button onClick={moveSelectedFilteredToValid} className="px-4 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white text-[10px] uppercase font-bold shadow-lg transition-all">Move to Valid</button>
              )}
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-widest transition-all ${selectedIds.size === 0 ? 'bg-gray-800 text-gray-600 cursor-not-allowed' : 'bg-green-600 text-white hover:bg-green-500 shadow-xl'}`}>
                {isDownloading ? 'Zipping...' : `Export (${selectedIds.size})`}
              </button>
            </div>
          </div>
          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; })}
              onToggleAll={(sel) => setSelectedIds(sel ? new Set(activeFrames.map(f => f.id)) : new Set())}
              onDelete={(id) => {
                setFrames(prev => prev.filter(f => f.id !== id));
                setFilteredFrames(prev => prev.filter(f => f.id !== id));
              }}
              onView={setPreviewFrame}
              onRestore={viewMode === 'filtered' ? moveFilteredToValid : undefined}
              onRefine={() => {}}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {previewFrame && (
          <RedactionViewer 
            frame={previewFrame} 
            onClose={() => setPreviewFrame(null)} 
            onSave={async (id, rects) => {
               const frame = [...frames, ...filteredFrames].find(f => f.id === id);
               if (frame) {
                 const redactedUrl = await applyRedaction(frame.dataUrl, rects);
                 const updateFn = (f: ExtractedFrame) => f.id === id ? { ...f, dataUrl: redactedUrl, redacted: true } : f;
                 setFrames(prev => prev.map(updateFn));
                 setFilteredFrames(prev => prev.map(updateFn));
                 setPreviewFrame(null);
               }
            }} 
          />
        )}
      </AnimatePresence>

      <div className="fixed bottom-8 right-8 z-[100]">
        <button onClick={captureManualSnapshot} className="w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-blue-400/20 shadow-2xl transition-all active:scale-95">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
        </button>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import * as ReactWindow from 'react-window';
import _AutoSizer from 'react-virtualized-auto-sizer';
import { motion, AnimatePresence } from 'framer-motion';
import { ExtractedFrame } from '../types';

const List = (ReactWindow as any).FixedSizeList;
const AutoSizer = _AutoSizer as any;

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  selectedIds: Set<string>;
  onToggleSelection: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onDelete: (id: string) => void;
  onView: (frame: ExtractedFrame) => void;
  onRestore?: (id: string) => void;
  onRefine: (frame: ExtractedFrame) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ 
  frames, 
  selectedIds, 
  onToggleSelection, 
  onToggleAll,
  onDelete,
  onView,
  onRestore
}) => {
  const allSelectedInCurrentView = frames.length > 0 && frames.every(f => selectedIds.has(f.id));

  const getGridConfig = (containerWidth: number) => {
    if (containerWidth < 640) return { columns: 1, gap: 16 };
    if (containerWidth < 1024) return { columns: 2, gap: 20 };
    if (containerWidth < 1440) return { columns: 3, gap: 24 };
    return { columns: 4, gap: 24 };
  };

  const FrameItem = ({ frame, isSelected }: { frame: ExtractedFrame, isSelected: boolean }) => {
    const isFiltered = !!frame.filterReason;

    return (
      <motion.div layout className={`group relative bg-gray-900 rounded-2xl overflow-hidden border transition-all duration-300 shadow-xl h-full flex flex-col ${isSelected ? 'border-blue-500 ring-4 ring-blue-500/10' : 'border-gray-800 hover:border-gray-600'}`}>
        <div className="aspect-video bg-gray-950 relative overflow-hidden flex-shrink-0 cursor-pointer" onClick={() => onToggleSelection(frame.id)}>
          <img src={frame.dataUrl} alt="Screen" className={`w-full h-full object-contain transition-transform duration-700 ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`} loading="lazy" />

          <div className="absolute top-3 left-3 w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all bg-black/40 border-white/20 backdrop-blur-md">
             {isSelected && <div className="w-2.5 h-2.5 bg-blue-500 rounded-sm" />}
          </div>

          <div className="absolute top-3 right-3 flex flex-col gap-1 items-end">
             {frame.redacted && <span className="bg-purple-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">Redacted</span>}
             {isFiltered ? (
               <span className="bg-orange-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">{frame.filterReason}</span>
             ) : (
               <span className="bg-green-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">Valid</span>
             )}
          </div>

          <div className="absolute bottom-2 left-2 bg-black/70 backdrop-blur text-[9px] font-bold font-mono py-0.5 px-2 rounded border border-white/10 text-blue-400">
            {frame.timestamp.toFixed(2)}s
          </div>
        </div>

        <div className="p-2 flex items-center justify-between bg-gray-900 mt-auto border-t border-gray-800">
          <button onClick={() => onView(frame)} className="p-1.5 bg-gray-800 hover:bg-blue-600/20 rounded-lg transition-all text-blue-400 border border-gray-700/50">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
          </button>

          <div className="flex gap-1.5">
            {onRestore && <button onClick={() => onRestore(frame.id)} className="p-1.5 bg-blue-600 hover:bg-blue-500 rounded-lg text-white"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>}
            <button onClick={() => onDelete(frame.id)} className="p-1.5 bg-gray-800 hover:bg-red-600/20 rounded-lg text-gray-500 hover:text-red-400 transition-all">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
          </div>
        </div>
      </motion.div>
    );
  };

  if (frames.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-20 bg-gray-950/40 rounded-3xl border-2 border-dashed border-gray-800 h-full">
        <p className="text-gray-500 font-black uppercase tracking-widest text-[10px]">No screens yet</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full gap-4">
      <div className="flex items-center gap-4 py-2 px-4 bg-gray-900 rounded-xl border border-gray-800 shadow-lg flex-shrink-0">
        <input type="checkbox" checked={allSelectedInCurrentView} onChange={(e) => onToggleAll(e.target.checked)} className="w-4 h-4 rounded bg-gray-800 border-gray-700" />
        <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">{frames.length} results</span>
      </div>

      <div className="flex-1 rounded-3xl overflow-hidden border border-gray-800/50 bg-gray-950 relative min-h-0">
        <AutoSizer>
          {({ height, width }: { height: number, width: number }) => {
            const { columns, gap } = getGridConfig(width);
            const columnWidth = (width - (columns + 1) * gap) / columns;
            const rowHeight = (columnWidth * (9/16)) + 50; 
            const rowCount = Math.ceil(frames.length / columns);

            return (
              <List height={height} itemCount={rowCount} itemSize={rowHeight + gap} width={width} itemData={{ columns, columnWidth, gap, frames, selectedIds }}>
                {({ index, style, data }: any) => {
                  const { columns, columnWidth, gap, frames, selectedIds } = data;
                  const rowFrames = frames.slice(index * columns, (index + 1) * columns);
                  return (
                    <div style={{ ...style, display: 'flex', paddingLeft: gap, paddingTop: gap }}>
                      {rowFrames.map((f: ExtractedFrame) => (
                        <div key={f.id} style={{ width: columnWidth, marginRight: gap, height: rowHeight }}>
                          <FrameItem frame={f} isSelected={selectedIds.has(f.id)} />
                        </div>
                      ))}
                    </div>
                  );
                }}
              </List>
            );
          }}
        </AutoSizer>
      </div>
    </div>
  );
};

export default FrameGallery;

export interface ExtractedFrame {
  id: string;
  timestamp: number;
  dataUrl: string;
  blurScore: number;
  hash: string;
  loadingScore: number; // Ratio of skeleton-like pixels detected
  textRatio: number;    // Ratio of text-like pixels detected
  isStable: boolean;
  isUnique: boolean;
  filterReason?: 'blurry' | 'duplicate' | 'manual-restored' | 'transition' | 'overlay' | 'loading' | 'typing' | 'dimmed';
  redacted?: boolean;
}

export interface FilterSettings {
  blurThreshold: number;
  similarityThreshold: number;
