        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const dataUrl = canvas.toDataURL('image/png');
        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const loading = getLoadingMetrics(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, loading, overlay, dataUrl });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setRawCandidates([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const candidates: ExtractedFrame[] = [];

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await new Promise(r => setTimeout(r, 40)); 

      const metadata = await getFrameMetadata(time);
      if (!metadata) continue;

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = post ? hammingDistance(metadata.hash, post.hash) : 0;
      const isSettled = postDiff <= 1; 

      candidates.push({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: time,
        dataUrl: metadata.dataUrl,
        blurScore: metadata.metrics.blurScore,
        hash: metadata.hash,
        loadingScore: metadata.loading.skeletonRatio,
        textRatio: metadata.loading.textRatio,
        isStable: isSettled,
        isUnique: true
      });

      setProgress(Math.min(100, (time / duration) * 100));
      if (candidates.length % 5 === 0) {
        setRawCandidates([...candidates]);
      }
    }

    setRawCandidates(candidates);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const { frames, filteredFrames } = useMemo(() => {
    const valid: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let lastHash = '';

    rawCandidates.forEach(cand => {
      let reason: ExtractedFrame['filterReason'] = undefined;

      if (cand.loadingScore > settings.loadingSensitivity && cand.textRatio < 0.05) {
        reason = 'loading';
      } 
      else if (cand.blurScore < settings.blurThreshold) {
        reason = 'blurry';
      }
      else {
        const dist = lastHash ? hammingDistance(cand.hash, lastHash) : 999;
        if (dist <= settings.similarityThreshold) {
          reason = 'duplicate';
        } else {
          lastHash = cand.hash;
        }
      }

      if (reason) {
        filtered.push({ ...cand, filterReason: reason });
      } else {
        valid.push(cand);
      }
    });

    return { frames: valid, filteredFrames: filtered };
  }, [rawCandidates, settings]);

  const autoBlurSelected = async () => {
    if (selectedIds.size === 0) return;
    setStatus(ProcessingStatus.AUTO_BLURRING);

    const framesToBlur = [...frames, ...filteredFrames].filter(f => selectedIds.has(f.id));

    for (const frame of framesToBlur) {
      const boxes = await detectPII(frame.dataUrl);
      if (boxes.length > 0) {
        const img = new Image();
        await new Promise((resolve) => {
          img.onload = resolve;
          img.src = frame.dataUrl;
        });

        const pixelRects = boxes.map(box => ({
          x: (box.xmin / 1000) * img.naturalWidth,
          y: (box.ymin / 1000) * img.naturalHeight,
          w: ((box.xmax - box.xmin) / 1000) * img.naturalWidth,
          h: ((box.ymax - box.ymin) / 1000) * img.naturalHeight
        }));

        const redactedUrl = await applyRedaction(frame.dataUrl, pixelRects);
        setRawCandidates(prev => prev.map(f => f.id === frame.id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
      }
    }

    setStatus(ProcessingStatus.COMPLETED);
  };

  const moveFilteredToValid = (id: string) => {
    setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, filterReason: 'manual-restored' as any, loadingScore: 0, blurScore: 9999 } : f));
    setSelectedIds(prev => new Set(prev).add(id));
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const all = [...frames, ...filteredFrames];
      const items = all.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);

      items.forEach((frame, idx) => {
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`${idx + 1}_${frame.timestamp.toFixed(2)}s.png`, base64Data, { base64: true });
      });

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `anatomi_screens_${new Date().getTime()}.zip`;
      link.click();
    } finally { setIsDownloading(false); }
  };

  const handleManualSnapshot = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    const dataUrl = canvas.toDataURL('image/png');
    const metrics = calculateImageMetrics(canvas);
    const hash = await calculateAverageHash(canvas);

    setRawCandidates(prev => [...prev, {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: video.currentTime,
      dataUrl,
      blurScore: metrics.blurScore,
      hash,
      loadingScore: 0,
      textRatio: 1,
      isStable: true,
      isUnique: true,
      filterReason: 'manual-restored'
    }].sort((a,b) => a.timestamp - b.timestamp));
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-8 min-h-screen flex flex-col relative bg-gray-950">
      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">Anatomi <span className="text-blue-500">Editor</span></h1>
          <p className="text-gray-400 text-xs mt-1 uppercase tracking-widest font-bold">Intelligent Extraction & PII Shield</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm shadow-lg">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            <span className="font-bold">Upload</span>
          </label>
          <button 
            disabled={!videoFile || status === ProcessingStatus.EXTRACTING} 
            onClick={processVideo} 
            className={`px-6 py-2.5 rounded-xl font-bold transition-all text-sm ${status === ProcessingStatus.EXTRACTING ? 'bg-blue-600/50 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg'}`}
          >
            {status === ProcessingStatus.EXTRACTING ? 'Processing...' : 'Extract Screens'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0">
        {/* Sidebar: Now lg:col-span-4 to make Video and Controls "big" */}
        <div className="lg:col-span-4 space-y-6">
          {/* 1st Place: Video Preview */}
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl">
            <h2 className="text-xs font-black mb-3 uppercase tracking-widest text-gray-500">Video Preview</h2>
            <div className="aspect-video bg-black rounded-xl overflow-hidden border border-gray-800 relative">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-full object-contain" controls /> : <div className="w-full h-full flex items-center justify-center text-gray-700 text-[10px] font-black uppercase">No source</div>}
              {status === ProcessingStatus.EXTRACTING && (
              <div className="absolute inset-0 bg-blue-600/10 flex items-center justify-center pointer-events-none">
                <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="w-12 h-12 border-2 border-blue-500/20 border-t-blue-500 rounded-full" />
              </div>
            )}
            </div>
            {status === ProcessingStatus.EXTRACTING && (
              <div className="mt-4">
                <div className="flex justify-between text-[10px] font-bold text-blue-400 uppercase mb-1">
                  <span>Extracting Frames</span>
                  <span>{Math.round(progress)}%</span>
                </div>
                <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                  <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="bg-blue-500 h-full" />
                </div>
              </div>
            )}
          </section>

          {/* 2nd Place: Filter Controls */}
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-5 shadow-xl">
            <h2 className="text-xs font-black mb-4 uppercase tracking-widest text-gray-500">Filter Controls</h2>

            <div className="space-y-6">
              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Sharpness Threshold</span>
                  <span className="text-blue-400 font-mono">{settings.blurThreshold}</span>
                </div>
                <input type="range" min="0" max="500" step="10" value={settings.blurThreshold} onChange={e => setSettings({...settings, blurThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>

              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Similarity Distance</span>
                  <span className="text-blue-400 font-mono">{settings.similarityThreshold}</span>
                </div>
                <input type="range" min="0" max="10" step="1" value={settings.similarityThreshold} onChange={e => setSettings({...settings, similarityThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>

              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Loading Sensitivity</span>
                  <span className="text-blue-400 font-mono">{(settings.loadingSensitivity * 100).toFixed(0)}%</span>
                </div>
                <input type="range" min="0.01" max="0.3" step="0.01" value={settings.loadingSensitivity} onChange={e => setSettings({...settings, loadingSensitivity: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 mt-8">
              <button onClick={() => setViewMode('valid')} className={`p-4 rounded-xl border transition-all text-left group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600 shadow-[0_0_15px_rgba(37,99,235,0.1)]' : 'bg-gray-800/50 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-2xl font-black ${viewMode === 'valid' ? 'text-blue-400' : 'text-white'}`}>{frames.length}</div>
                <div className="text-[9px] text-gray-500 uppercase font-black tracking-tighter">Valid Screens</div>
              </button>
              <button onClick={() => setViewMode('filtered')} className={`p-4 rounded-xl border transition-all text-left group ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600 shadow-[0_0_15px_rgba(234,88,12,0.1)]' : 'bg-gray-800/50 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-2xl font-black ${viewMode === 'filtered' ? 'text-orange-400' : 'text-white'}`}>{filteredFrames.length}</div>
                <div className="text-[9px] text-gray-500 uppercase font-black tracking-tighter">Filtered Out</div>
              </button>
            </div>
          </section>
        </div>

        {/* Gallery Section */}
        <div className="lg:col-span-8 flex flex-col gap-4">
          <div className="bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex items-center justify-between backdrop-blur-sm">
            <h2 className="text-xl font-bold text-white capitalize flex items-center gap-2">
              <span className={viewMode === 'valid' ? 'text-blue-500' : 'text-orange-500'}>●</span>
              {viewMode} Results
            </h2>
            <div className="flex items-center gap-3">
              {selectedIds.size > 0 && (
                <button 
                  onClick={autoBlurSelected} 
                  disabled={status === ProcessingStatus.AUTO_BLURRING}
                  className={`px-4 py-2 rounded-xl text-white text-[10px] uppercase font-bold shadow-lg transition-all flex items-center gap-2 ${status === ProcessingStatus.AUTO_BLURRING ? 'bg-purple-600/50' : 'bg-purple-600 hover:bg-purple-500 active:scale-95'}`}
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                  {status === ProcessingStatus.AUTO_BLURRING ? 'Redacting PII...' : 'Auto-Blur PII'}
                </button>
              )}
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-widest transition-all ${selectedIds.size === 0 ? 'bg-gray-800 text-gray-600 cursor-not-allowed' : 'bg-green-600 text-white hover:bg-green-500 shadow-xl active:scale-95'}`}>
                {isDownloading ? 'Zipping...' : `Export Selected (${selectedIds.size})`}
              </button>
            </div>
          </div>
          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; })}
              onToggleAll={(sel) => setSelectedIds(sel ? new Set(activeFrames.map(f => f.id)) : new Set())}
              onDelete={(id) => setRawCandidates(prev => prev.filter(f => f.id !== id))}
              onView={setPreviewFrame}
              onRestore={viewMode === 'filtered' ? moveFilteredToValid : undefined}
              onRefine={() => {}}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {previewFrame && (
          <RedactionViewer 
            frame={previewFrame} 
            onClose={() => setPreviewFrame(null)} 
            onSave={async (id, rects) => {
               const redactedUrl = await applyRedaction(previewFrame.dataUrl, rects);
               setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
               setPreviewFrame(null);
            }} 
          />
        )}
      </AnimatePresence>

      <canvas ref={canvasRef} className="hidden" />

      <div className="fixed bottom-8 right-8 z-[100]">
        <button onClick={handleManualSnapshot} className="w-16 h-16 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-blue-400/20 shadow-2xl transition-all active:scale-90 group">
          <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
        </button>
      </div>
    </div>
  );
};

export default App;

export interface ExtractedFrame {
  id: string;
  timestamp: number;
  dataUrl: string;
  originalDataUrl: string; // Keep source to allow undo
  blurScore: number;
  hash: string;
  loadingScore: number; // Ratio of skeleton-like pixels detected
  textRatio: number;    // Ratio of text-like pixels detected
  isStable: boolean;
  isUnique: boolean;
  filterReason?: 'blurry' | 'duplicate' | 'manual-restored' | 'transition' | 'overlay' | 'loading' | 'typing' | 'dimmed';
  redacted?: boolean;
}

export interface FilterSettings {
  blurThreshold: number;
  similarityThreshold: number;
  loadingSensitivity: number;
  showDimmed: boolean;
}

export interface ProcessingStats {
  totalFramesAnalyzed: number;
  duplicateCount: number;
  blurryCount: number;
  stableCount: number;
  transitionCount: number;
  loadingCount: number;
  typingCount: number;
  dimmedCount: number;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  EXTRACTING = 'EXTRACTING',
  COMPLETED = 'COMPLETED',
  AUTO_BLURRING = 'AUTO_BLURRING'
}

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats, FilterSettings } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, getLoadingMetrics, analyzeOverlayState, applyRedaction } from './services/videoProcessor';
import { detectPII, BoundingBox } from './services/geminiService';
import FrameGallery from './components/FrameGallery';
import RedactionViewer from './components/RedactionViewer';

const FRAME_INTERVAL = 0.5; 
const TEMPORAL_LOOKAHEAD = 0.15; 

type ViewMode = 'valid' | 'filtered';

interface FrameMetadata {
  hash: string;
  metrics: { blurScore: number, edgeIntensity: number };
  loading: { skeletonRatio: number, textRatio: number, bgRatio: number };
  overlay: { isDimmed: boolean, hasPopup: boolean };
  dataUrl: string;
}

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [rawCandidates, setRawCandidates] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [previewFrame, setPreviewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);

  const [settings, setSettings] = useState<FilterSettings>({
    blurThreshold: 180,
    similarityThreshold: 1,
    loadingSensitivity: 0.08,
    showDimmed: false
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('video/')) {
      alert('Invalid file type.');
      return;
    }
    setRawCandidates([]);
    setSelectedIds(new Set());
    setPreviewFrame(null);
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');
    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const getFrameMetadata = async (time: number): Promise<FrameMetadata | null> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return null;

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) {
          resolve(null);
          return;
        }

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const dataUrl = canvas.toDataURL('image/png');
        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const loading = getLoadingMetrics(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, loading, overlay, dataUrl });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setRawCandidates([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const candidates: ExtractedFrame[] = [];

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await new Promise(r => setTimeout(r, 40)); 

      const metadata = await getFrameMetadata(time);
      if (!metadata) continue;

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = post ? hammingDistance(metadata.hash, post.hash) : 0;
      const isSettled = postDiff <= 1; 

      candidates.push({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: time,
        dataUrl: metadata.dataUrl,
        originalDataUrl: metadata.dataUrl,
        blurScore: metadata.metrics.blurScore,
        hash: metadata.hash,
        loadingScore: metadata.loading.skeletonRatio,
        textRatio: metadata.loading.textRatio,
        isStable: isSettled,
        isUnique: true
      });

      setProgress(Math.min(100, (time / duration) * 100));
      if (candidates.length % 5 === 0) {
        setRawCandidates([...candidates]);
      }
    }

    setRawCandidates(candidates);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const { frames, filteredFrames } = useMemo(() => {
    const valid: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let lastHash = '';

    rawCandidates.forEach(cand => {
      let reason: ExtractedFrame['filterReason'] = undefined;

      if (cand.loadingScore > settings.loadingSensitivity && cand.textRatio < 0.05) {
        reason = 'loading';
      } 
      else if (cand.blurScore < settings.blurThreshold) {
        reason = 'blurry';
      }
      else {
        const dist = lastHash ? hammingDistance(cand.hash, lastHash) : 999;
        if (dist <= settings.similarityThreshold) {
          reason = 'duplicate';
        } else {
          lastHash = cand.hash;
        }
      }

      if (reason) {
        filtered.push({ ...cand, filterReason: reason });
      } else {
        valid.push(cand);
      }
    });

    return { frames: valid, filteredFrames: filtered };
  }, [rawCandidates, settings]);

  const autoBlurSelected = async () => {
    if (selectedIds.size === 0) return;
    setStatus(ProcessingStatus.AUTO_BLURRING);

    const framesToBlur = [...frames, ...filteredFrames].filter(f => selectedIds.has(f.id));

    for (const frame of framesToBlur) {
      // Always detect on original URL to ensure best accuracy and consistency
      const boxes = await detectPII(frame.originalDataUrl);
      if (boxes.length > 0) {
        const img = new Image();
        await new Promise((resolve) => {
          img.onload = resolve;
          img.src = frame.originalDataUrl;
        });

        const pixelRects = boxes.map(box => ({
          x: (box.xmin / 1000) * img.naturalWidth,
          y: (box.ymin / 1000) * img.naturalHeight,
          w: ((box.xmax - box.xmin) / 1000) * img.naturalWidth,
          h: ((box.ymax - box.ymin) / 1000) * img.naturalHeight
        }));

        const redactedUrl = await applyRedaction(frame.originalDataUrl, pixelRects);
        setRawCandidates(prev => prev.map(f => f.id === frame.id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
      }
    }

    setStatus(ProcessingStatus.COMPLETED);
  };

  const handleUndoRedaction = useCallback((id: string) => {
    setRawCandidates(prev => prev.map(f => 
      f.id === id ? { ...f, dataUrl: f.originalDataUrl, redacted: false } : f
    ));
  }, []);

  const handleUndoSelectedRedaction = useCallback(() => {
    setRawCandidates(prev => prev.map(f => 
      selectedIds.has(f.id) ? { ...f, dataUrl: f.originalDataUrl, redacted: false } : f
    ));
  }, [selectedIds]);

  const moveFilteredToValid = (id: string) => {
    setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, filterReason: 'manual-restored' as any, loadingScore: 0, blurScore: 9999 } : f));
    setSelectedIds(prev => new Set(prev).add(id));
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const all = [...frames, ...filteredFrames];
      const items = all.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);

      items.forEach((frame, idx) => {
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`${idx + 1}_${frame.timestamp.toFixed(2)}s.png`, base64Data, { base64: true });
      });

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `anatomi_screens_${new Date().getTime()}.zip`;
      link.click();
    } finally { setIsDownloading(false); }
  };

  const handleManualSnapshot = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    const dataUrl = canvas.toDataURL('image/png');
    const metrics = calculateImageMetrics(canvas);
    const hash = await calculateAverageHash(canvas);

    setRawCandidates(prev => [...prev, {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: video.currentTime,
      dataUrl,
      originalDataUrl: dataUrl,
      blurScore: metrics.blurScore,
      hash,
      loadingScore: 0,
      textRatio: 1,
      isStable: true,
      isUnique: true,
      filterReason: 'manual-restored'
    }].sort((a,b) => a.timestamp - b.timestamp));
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;
  const anySelectedIsRedacted = useMemo(() => {
    return activeFrames.some(f => selectedIds.has(f.id) && f.redacted);
  }, [activeFrames, selectedIds]);

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-8 min-h-screen flex flex-col relative bg-gray-950">
      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">Anatomi <span className="text-blue-500">Editor</span></h1>
          <p className="text-gray-400 text-xs mt-1 uppercase tracking-widest font-bold">Intelligent Extraction & PII Shield</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm shadow-lg">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            <span className="font-bold">Upload</span>
          </label>
          <button 
            disabled={!videoFile || status === ProcessingStatus.EXTRACTING} 
            onClick={processVideo} 
            className={`px-6 py-2.5 rounded-xl font-bold transition-all text-sm ${status === ProcessingStatus.EXTRACTING ? 'bg-blue-600/50 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg'}`}
          >
            {status === ProcessingStatus.EXTRACTING ? 'Processing...' : 'Extract Screens'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0">
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl">
            <h2 className="text-xs font-black mb-3 uppercase tracking-widest text-gray-500">Video Preview</h2>
            <div className="aspect-video bg-black rounded-xl overflow-hidden border border-gray-800 relative">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-full object-contain" controls /> : <div className="w-full h-full flex items-center justify-center text-gray-700 text-[10px] font-black uppercase">No source</div>}
              {status === ProcessingStatus.EXTRACTING && (
              <div className="absolute inset-0 bg-blue-600/10 flex items-center justify-center pointer-events-none">
                <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="w-12 h-12 border-2 border-blue-500/20 border-t-blue-500 rounded-full" />
              </div>
            )}
            </div>
            {status === ProcessingStatus.EXTRACTING && (
              <div className="mt-4">
                <div className="flex justify-between text-[10px] font-bold text-blue-400 uppercase mb-1">
                  <span>Extracting Frames</span>
                  <span>{Math.round(progress)}%</span>
                </div>
                <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                  <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="bg-blue-500 h-full" />
                </div>
              </div>
            )}
          </section>

          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-5 shadow-xl">
            <h2 className="text-xs font-black mb-4 uppercase tracking-widest text-gray-500">Filter Controls</h2>

            <div className="space-y-6">
              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Sharpness Threshold</span>
                  <span className="text-blue-400 font-mono">{settings.blurThreshold}</span>
                </div>
                <input type="range" min="0" max="500" step="10" value={settings.blurThreshold} onChange={e => setSettings({...settings, blurThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>

              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Similarity Distance</span>
                  <span className="text-blue-400 font-mono">{settings.similarityThreshold}</span>
                </div>
                <input type="range" min="0" max="10" step="1" value={settings.similarityThreshold} onChange={e => setSettings({...settings, similarityThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>

              <div>
                <div className="flex justify-between text-[10px] font-black uppercase text-gray-400 mb-2">
                  <span>Loading Sensitivity</span>
                  <span className="text-blue-400 font-mono">{(settings.loadingSensitivity * 100).toFixed(0)}%</span>
                </div>
                <input type="range" min="0.01" max="0.3" step="0.01" value={settings.loadingSensitivity} onChange={e => setSettings({...settings, loadingSensitivity: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-1.5 rounded-lg appearance-none cursor-pointer" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 mt-8">
              <button onClick={() => setViewMode('valid')} className={`p-4 rounded-xl border transition-all text-left group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600 shadow-[0_0_15px_rgba(37,99,235,0.1)]' : 'bg-gray-800/50 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-2xl font-black ${viewMode === 'valid' ? 'text-blue-400' : 'text-white'}`}>{frames.length}</div>
                <div className="text-[9px] text-gray-500 uppercase font-black tracking-tighter">Valid Screens</div>
              </button>
              <button onClick={() => setViewMode('filtered')} className={`p-4 rounded-xl border transition-all text-left group ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600 shadow-[0_0_15px_rgba(234,88,12,0.1)]' : 'bg-gray-800/50 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-2xl font-black ${viewMode === 'filtered' ? 'text-orange-400' : 'text-white'}`}>{filteredFrames.length}</div>
                <div className="text-[9px] text-gray-500 uppercase font-black tracking-tighter">Filtered Out</div>
              </button>
            </div>
          </section>
        </div>

        <div className="lg:col-span-8 flex flex-col gap-4">
          <div className="bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex items-center justify-between backdrop-blur-sm">
            <h2 className="text-xl font-bold text-white capitalize flex items-center gap-2">
              <span className={viewMode === 'valid' ? 'text-blue-500' : 'text-orange-500'}>●</span>
              {viewMode} Results
            </h2>
            <div className="flex items-center gap-3">
              {selectedIds.size > 0 && (
                <div className="flex gap-2">
                  {anySelectedIsRedacted && (
                    <button 
                      onClick={handleUndoSelectedRedaction}
                      className="px-4 py-2 rounded-xl text-orange-400 hover:text-white hover:bg-orange-600/20 text-[10px] uppercase font-bold shadow-lg transition-all border border-orange-600/30 flex items-center gap-2"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
                      Undo Blur
                    </button>
                  )}
                  <button 
                    onClick={autoBlurSelected} 
                    disabled={status === ProcessingStatus.AUTO_BLURRING}
                    className={`px-4 py-2 rounded-xl text-white text-[10px] uppercase font-bold shadow-lg transition-all flex items-center gap-2 ${status === ProcessingStatus.AUTO_BLURRING ? 'bg-purple-600/50' : 'bg-purple-600 hover:bg-purple-500 active:scale-95'}`}
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                    {status === ProcessingStatus.AUTO_BLURRING ? 'Redacting PII...' : 'Auto-Blur PII'}
                  </button>
                </div>
              )}
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-widest transition-all ${selectedIds.size === 0 ? 'bg-gray-800 text-gray-600 cursor-not-allowed' : 'bg-green-600 text-white hover:bg-green-500 shadow-xl active:scale-95'}`}>
                {isDownloading ? 'Zipping...' : `Export Selected (${selectedIds.size})`}
              </button>
            </div>
          </div>
          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; })}
              onToggleAll={(sel) => setSelectedIds(sel ? new Set(activeFrames.map(f => f.id)) : new Set())}
              onDelete={(id) => setRawCandidates(prev => prev.filter(f => f.id !== id))}
              onView={setPreviewFrame}
              onRestore={viewMode === 'filtered' ? moveFilteredToValid : undefined}
              onUndoBlur={handleUndoRedaction}
              onRefine={() => {}}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {previewFrame && (
          <RedactionViewer 
            frame={previewFrame} 
            onClose={() => setPreviewFrame(null)} 
            onSave={async (id, rects) => {
               const redactedUrl = await applyRedaction(previewFrame.originalDataUrl, rects);
               setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
               setPreviewFrame(null);
            }} 
          />
        )}
      </AnimatePresence>

      <canvas ref={canvasRef} className="hidden" />

      <div className="fixed bottom-8 right-8 z-[100]">
        <button onClick={handleManualSnapshot} className="w-16 h-16 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-blue-400/20 shadow-2xl transition-all active:scale-90 group">
          <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
        </button>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import * as ReactWindow from 'react-window';
import _AutoSizer from 'react-virtualized-auto-sizer';
import { motion, AnimatePresence } from 'framer-motion';
import { ExtractedFrame } from '../types';

const List = (ReactWindow as any).FixedSizeList;
const AutoSizer = _AutoSizer as any;

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  selectedIds: Set<string>;
  onToggleSelection: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onDelete: (id: string) => void;
  onView: (frame: ExtractedFrame) => void;
  onRestore?: (id: string) => void;
  onUndoBlur?: (id: string) => void;
  onRefine: (frame: ExtractedFrame) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ 
  frames, 
  selectedIds, 
  onToggleSelection, 
  onToggleAll,
  onDelete,
  onView,
  onRestore,
  onUndoBlur
}) => {
  const allSelectedInCurrentView = frames.length > 0 && frames.every(f => selectedIds.has(f.id));

  const getGridConfig = (containerWidth: number) => {
    if (containerWidth < 640) return { columns: 1, gap: 16 };
    if (containerWidth < 1024) return { columns: 2, gap: 20 };
    if (containerWidth < 1440) return { columns: 3, gap: 24 };
    return { columns: 4, gap: 24 };
  };

  const FrameItem = ({ frame, isSelected }: { frame: ExtractedFrame, isSelected: boolean }) => {
    const isFiltered = !!frame.filterReason;

    return (
      <motion.div layout className={`group relative bg-gray-900 rounded-2xl overflow-hidden border transition-all duration-300 shadow-xl h-full flex flex-col ${isSelected ? 'border-blue-500 ring-4 ring-blue-500/10' : 'border-gray-800 hover:border-gray-600'}`}>
        <div className="aspect-video bg-gray-950 relative overflow-hidden flex-shrink-0 cursor-pointer" onClick={() => onToggleSelection(frame.id)}>
          <img src={frame.dataUrl} alt="Screen" className={`w-full h-full object-contain transition-transform duration-700 ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`} loading="lazy" />

          <div className="absolute top-3 left-3 w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all bg-black/40 border-white/20 backdrop-blur-md">
             {isSelected && <div className="w-2.5 h-2.5 bg-blue-500 rounded-sm" />}
          </div>

          <div className="absolute top-3 right-3 flex flex-col gap-1 items-end">
             {frame.redacted && <span className="bg-purple-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">Redacted</span>}
             {isFiltered ? (
               <span className="bg-orange-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">{frame.filterReason}</span>
             ) : (
               <span className="bg-green-600 text-white text-[7px] px-1.5 py-0.5 rounded font-black uppercase tracking-wider shadow-lg">Valid</span>
             )}
          </div>

          <div className="absolute bottom-2 left-2 bg-black/70 backdrop-blur text-[9px] font-bold font-mono py-0.5 px-2 rounded border border-white/10 text-blue-400">
            {frame.timestamp.toFixed(2)}s
          </div>
        </div>

        <div className="p-2 flex items-center justify-between bg-gray-900 mt-auto border-t border-gray-800">
          <div className="flex gap-1.5">
            <button onClick={() => onView(frame)} title="View/Edit Blur" className="p-1.5 bg-gray-800 hover:bg-blue-600/20 rounded-lg transition-all text-blue-400 border border-gray-700/50">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
            </button>
            {frame.redacted && onUndoBlur && (
              <button onClick={() => onUndoBlur(frame.id)} title="Undo Blur" className="p-1.5 bg-gray-800 hover:bg-orange-600/20 rounded-lg transition-all text-orange-400 border border-gray-700/50">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
              </button>
            )}
          </div>

          <div className="flex gap-1.5">
            {onRestore && <button onClick={() => onRestore(frame.id)} className="p-1.5 bg-blue-600 hover:bg-blue-500 rounded-lg text-white"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>}
            <button onClick={() => onDelete(frame.id)} className="p-1.5 bg-gray-800 hover:bg-red-600/20 rounded-lg text-gray-500 hover:text-red-400 transition-all">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
          </div>
        </div>
      </motion.div>
    );
  };

  if (frames.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-20 bg-gray-950/40 rounded-3xl border-2 border-dashed border-gray-800 h-full">
        <p className="text-gray-500 font-black uppercase tracking-widest text-[10px]">No screens yet</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full gap-4">
      <div className="flex items-center gap-4 py-2 px-4 bg-gray-900 rounded-xl border border-gray-800 shadow-lg flex-shrink-0">
        <input type="checkbox" checked={allSelectedInCurrentView} onChange={(e) => onToggleAll(e.target.checked)} className="w-4 h-4 rounded bg-gray-800 border-gray-700" />
        <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">{frames.length} results</span>
      </div>

      <div className="flex-1 rounded-3xl overflow-hidden border border-gray-800/50 bg-gray-950 relative min-h-0">
        <AutoSizer>
          {({ height, width }: { height: number, width: number }) => {
            const { columns, gap } = getGridConfig(width);
            const columnWidth = (width - (columns + 1) * gap) / columns;
            const rowHeight = (columnWidth * (9/16)) + 50; 
            const rowCount = Math.ceil(frames.length / columns);

            return (
              <List height={height} itemCount={rowCount} itemSize={rowHeight + gap} width={width} itemData={{ columns, columnWidth, gap, frames, selectedIds }}>
                {({ index, style, data }: any) => {
                  const { columns, columnWidth, gap, frames, selectedIds } = data;
                  const rowFrames = frames.slice(index * columns, (index + 1) * columns);
                  return (
                    <div style={{ ...style, display: 'flex', paddingLeft: gap, paddingTop: gap }}>
                      {rowFrames.map((f: ExtractedFrame) => (
                        <div key={f.id} style={{ width: columnWidth, marginRight: gap, height: rowHeight }}>
                          <FrameItem frame={f} isSelected={selectedIds.has(f.id)} />
                        </div>
                      ))}
                    </div>
                  );
                }}
              </List>
            );
          }}
        </AutoSizer>
      </div>
    </div>
  );
};

export default FrameGallery;

export interface ExtractedFrame {
  id: string;
  timestamp: number;
  dataUrl: string;
  originalDataUrl: string; // Keep source to allow undo and high-quality re-processing
  blurScore: number;
  hash: string;
  loadingScore: number; // Ratio of skeleton-like pixels detected
  textRatio: number;    // Ratio of text-like pixels detected
  isStable: boolean;
  isUnique: boolean;
  filterReason?: 'blurry' | 'duplicate' | 'manual-restored' | 'transition' | 'overlay' | 'loading' | 'typing' | 'dimmed';
  redacted?: boolean;
}

export interface FilterSettings {
  blurThreshold: number;
  similarityThreshold: number;
  loadingSensitivity: number;
  showDimmed: boolean;
}

export interface ProcessingStats {
  totalFramesAnalyzed: number;
  duplicateCount: number;
  blurryCount: number;
  stableCount: number;
  transitionCount: number;
  loadingCount: number;
  typingCount: number;
  dimmedCount: number;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  EXTRACTING = 'EXTRACTING',
  COMPLETED = 'COMPLETED',
  AUTO_BLURRING = 'AUTO_BLURRING'
}

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats, FilterSettings } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, getLoadingMetrics, analyzeOverlayState, applyRedaction } from './services/videoProcessor';
import { detectPII, BoundingBox } from './services/geminiService';
import FrameGallery from './components/FrameGallery';
import RedactionViewer from './components/RedactionViewer';

const FRAME_INTERVAL = 0.5; 
const TEMPORAL_LOOKAHEAD = 0.15; 

type ViewMode = 'valid' | 'filtered';

interface FrameMetadata {
  hash: string;
  metrics: { blurScore: number, edgeIntensity: number };
  loading: { skeletonRatio: number, textRatio: number, bgRatio: number };
  overlay: { isDimmed: boolean, hasPopup: boolean };
  dataUrl: string;
}

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [rawCandidates, setRawCandidates] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [previewFrame, setPreviewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);

  const [settings, setSettings] = useState<FilterSettings>({
    blurThreshold: 180,
    similarityThreshold: 1,
    loadingSensitivity: 0.08,
    showDimmed: false
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('video/')) {
      alert('Invalid file type.');
      return;
    }
    setRawCandidates([]);
    setSelectedIds(new Set());
    setPreviewFrame(null);
    setStatus(ProcessingStatus.IDLE);
    setViewMode('valid');
    setVideoFile(file);
    setVideoUrl(URL.createObjectURL(file));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const getFrameMetadata = async (time: number): Promise<FrameMetadata | null> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return null;

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) {
          resolve(null);
          return;
        }

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const dataUrl = canvas.toDataURL('image/png');
        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const loading = getLoadingMetrics(canvas);
        const overlay = analyzeOverlayState(canvas);
        resolve({ hash, metrics, loading, overlay, dataUrl });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setRawCandidates([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const candidates: ExtractedFrame[] = [];

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await new Promise(r => setTimeout(r, 40)); 

      const metadata = await getFrameMetadata(time);
      if (!metadata) continue;

      const post = await getFrameMetadata(Math.min(duration, time + TEMPORAL_LOOKAHEAD));
      const postDiff = post ? hammingDistance(metadata.hash, post.hash) : 0;
      const isSettled = postDiff <= 1; 

      candidates.push({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: time,
        dataUrl: metadata.dataUrl,
        originalDataUrl: metadata.dataUrl, // Save source for undo
        blurScore: metadata.metrics.blurScore,
        hash: metadata.hash,
        loadingScore: metadata.loading.skeletonRatio,
        textRatio: metadata.loading.textRatio,
        isStable: isSettled,
        isUnique: true
      });

      setProgress(Math.min(100, (time / duration) * 100));
      if (candidates.length % 5 === 0) {
        setRawCandidates([...candidates]);
      }
    }

    setRawCandidates(candidates);
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const { frames, filteredFrames } = useMemo(() => {
    const valid: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    let lastHash = '';

    rawCandidates.forEach(cand => {
      let reason: ExtractedFrame['filterReason'] = undefined;

      if (cand.loadingScore > settings.loadingSensitivity && cand.textRatio < 0.05) {
        reason = 'loading';
      } 
      else if (cand.blurScore < settings.blurThreshold) {
        reason = 'blurry';
      }
      else {
        const dist = lastHash ? hammingDistance(cand.hash, lastHash) : 999;
        if (dist <= settings.similarityThreshold) {
          reason = 'duplicate';
        } else {
          lastHash = cand.hash;
        }
      }

      if (reason) {
        filtered.push({ ...cand, filterReason: reason });
      } else {
        valid.push(cand);
      }
    });

    return { frames: valid, filteredFrames: filtered };
  }, [rawCandidates, settings]);

  const autoBlurSelected = async () => {
    if (selectedIds.size === 0) return;
    setStatus(ProcessingStatus.AUTO_BLURRING);

    const framesToBlur = [...frames, ...filteredFrames].filter(f => selectedIds.has(f.id));

    for (const frame of framesToBlur) {
      // Always scan the original source image for PII
      const boxes = await detectPII(frame.originalDataUrl);
      if (boxes.length > 0) {
        const img = new Image();
        await new Promise((resolve) => {
          img.onload = resolve;
          img.src = frame.originalDataUrl;
        });

        const pixelRects = boxes.map(box => ({
          x: (box.xmin / 1000) * img.naturalWidth,
          y: (box.ymin / 1000) * img.naturalHeight,
          w: ((box.xmax - box.xmin) / 1000) * img.naturalWidth,
          h: ((box.ymax - box.ymin) / 1000) * img.naturalHeight
        }));

        const redactedUrl = await applyRedaction(frame.originalDataUrl, pixelRects);
        setRawCandidates(prev => prev.map(f => f.id === frame.id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
      }
    }

    setStatus(ProcessingStatus.COMPLETED);
  };

  const handleUndoRedaction = useCallback((id: string) => {
    setRawCandidates(prev => prev.map(f => 
      f.id === id ? { ...f, dataUrl: f.originalDataUrl, redacted: false } : f
    ));
  }, []);

  const handleUndoSelectedRedaction = useCallback(() => {
    setRawCandidates(prev => prev.map(f => 
      selectedIds.has(f.id) ? { ...f, dataUrl: f.originalDataUrl, redacted: false } : f
    ));
  }, [selectedIds]);

  const moveFilteredToValid = (id: string) => {
    setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, filterReason: 'manual-restored' as any, loadingScore: 0, blurScore: 9999 } : f));
    setSelectedIds(prev => new Set(prev).add(id));
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const all = [...frames, ...filteredFrames];
      const items = all.filter(f => selectedIds.has(f.id)).sort((a, b) => a.timestamp - b.timestamp);

      items.forEach((frame, idx) => {
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`${idx + 1}_${frame.timestamp.toFixed(2)}s.png`, base64Data, { base64: true });
      });

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `anatomi_screens_${new Date().getTime()}.zip`;
      link.click();
    } finally { setIsDownloading(false); }
  };

  const handleManualSnapshot = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    const dataUrl = canvas.toDataURL('image/png');
    const metrics = calculateImageMetrics(canvas);
    const hash = await calculateAverageHash(canvas);

    setRawCandidates(prev => [...prev, {
      id: `manual-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: video.currentTime,
      dataUrl,
      originalDataUrl: dataUrl,
      blurScore: metrics.blurScore,
      hash,
      loadingScore: 0,
      textRatio: 1,
      isStable: true,
      isUnique: true,
      filterReason: 'manual-restored'
    }].sort((a,b) => a.timestamp - b.timestamp));
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;
  const anySelectedIsRedacted = useMemo(() => {
    return activeFrames.some(f => selectedIds.has(f.id) && f.redacted);
  }, [activeFrames, selectedIds]);

  return (
    <div className="max-w-[1800px] mx-auto px-6 py-10 min-h-screen flex flex-col relative bg-gray-950">
      <header className="mb-8 flex flex-col md:flex-row md:items-center md:justify-between gap-8">
        <div>
          <h1 className="text-4xl font-black tracking-tight text-white">Anatomi <span className="text-blue-500">Editor</span></h1>
          <p className="text-gray-500 text-[10px] mt-1 uppercase tracking-[0.3em] font-black">Intelligent Frame Intelligence & Privacy Shield</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-5">
          <label className="cursor-pointer bg-gray-900/50 hover:bg-gray-800 text-white px-6 py-3 rounded-2xl border border-gray-800 transition-all flex items-center justify-center gap-3 text-sm font-black shadow-2xl">
            <svg className="w-5 h-5 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
            UPLOAD VIDEO
          </label>
          <button 
            disabled={!videoFile || status === ProcessingStatus.EXTRACTING} 
            onClick={processVideo} 
            className={`px-8 py-3 rounded-2xl font-black transition-all text-sm tracking-widest ${status === ProcessingStatus.EXTRACTING ? 'bg-blue-600/30 text-blue-300 cursor-not-allowed border border-blue-600/20' : 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.3)]'}`}
          >
            {status === ProcessingStatus.EXTRACTING ? 'EXTRACTING...' : 'RUN SMART EXTRACTION'}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-10 flex-1 min-h-0">
        {/* Expanded Sidebar for Larger Video Presence */}
        <div className="lg:col-span-5 space-y-10">
          {/* Main Video View - Large and Central in Sidebar */}
          <section className="bg-gray-900/40 rounded-3xl border border-gray-800 p-6 shadow-2xl backdrop-blur-md">
            <div className="flex items-center justify-between mb-5">
               <h2 className="text-[10px] font-black uppercase tracking-[0.25em] text-gray-500">Video Source Monitor</h2>
               {videoUrl && <span className="px-2 py-0.5 bg-blue-500/10 text-blue-400 text-[8px] font-black rounded border border-blue-500/20 uppercase">HD Live</span>}
            </div>
            <div className="bg-black rounded-2xl overflow-hidden border border-gray-800 relative shadow-inner ring-1 ring-white/5">
              {videoUrl ? <video ref={videoRef} src={videoUrl} className="w-full h-auto max-h-[600px] object-contain" controls /> : (
                <div className="aspect-video w-full flex flex-col items-center justify-center gap-4 text-gray-700">
                  <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  <p className="text-[10px] font-black uppercase tracking-widest">No Active Signal</p>
                </div>
              )}
              {status === ProcessingStatus.EXTRACTING && (
                <div className="absolute inset-0 bg-gray-950/60 backdrop-blur-sm flex items-center justify-center">
                  <div className="flex flex-col items-center gap-6">
                    <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1.5, ease: "linear" }} className="w-20 h-20 border-4 border-blue-500/10 border-t-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.2)]" />
                    <div className="text-center">
                      <div className="text-3xl font-black text-white">{Math.round(progress)}%</div>
                      <div className="text-[9px] font-black text-blue-400 uppercase tracking-widest mt-1">Deep Scanning Frames</div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </section>

          {/* Precision Controls */}
          <section className="bg-gray-900/40 rounded-3xl border border-gray-800 p-8 shadow-2xl backdrop-blur-md">
            <h2 className="text-[10px] font-black mb-8 uppercase tracking-[0.25em] text-gray-500">Extraction Heuristics</h2>

            <div className="space-y-10">
              <div>
                <div className="flex justify-between text-[11px] font-black uppercase text-gray-300 mb-4">
                  <span>Sharpness Threshold</span>
                  <span className="text-blue-400 font-mono text-xs">{settings.blurThreshold}</span>
                </div>
                <input type="range" min="0" max="500" step="10" value={settings.blurThreshold} onChange={e => setSettings({...settings, blurThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-2 rounded-xl appearance-none cursor-pointer" />
                <p className="text-[9px] text-gray-500 mt-3 italic">Higher = stricter sharpness requirements.</p>
              </div>

              <div>
                <div className="flex justify-between text-[11px] font-black uppercase text-gray-300 mb-4">
                  <span>Visual Redundancy</span>
                  <span className="text-blue-400 font-mono text-xs">{settings.similarityThreshold}</span>
                </div>
                <input type="range" min="0" max="10" step="1" value={settings.similarityThreshold} onChange={e => setSettings({...settings, similarityThreshold: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-2 rounded-xl appearance-none cursor-pointer" />
                <p className="text-[9px] text-gray-500 mt-3 italic">Controls uniqueness of exported frames.</p>
              </div>

              <div>
                <div className="flex justify-between text-[11px] font-black uppercase text-gray-300 mb-4">
                  <span>Loading State Filter</span>
                  <span className="text-blue-400 font-mono text-xs">{(settings.loadingSensitivity * 100).toFixed(0)}%</span>
                </div>
                <input type="range" min="0.01" max="0.3" step="0.01" value={settings.loadingSensitivity} onChange={e => setSettings({...settings, loadingSensitivity: Number(e.target.value)})} className="w-full accent-blue-500 bg-gray-800 h-2 rounded-xl appearance-none cursor-pointer" />
                <p className="text-[9px] text-gray-500 mt-3 italic">Sensitivity to skeleton-loader detection.</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4 mt-12">
              <button onClick={() => setViewMode('valid')} className={`p-6 rounded-2xl border transition-all text-left relative overflow-hidden group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_20px_rgba(37,99,235,0.15)]' : 'bg-gray-800/40 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-4xl font-black mb-1 ${viewMode === 'valid' ? 'text-blue-400' : 'text-white'}`}>{frames.length}</div>
                <div className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Valid</div>
                {viewMode === 'valid' && <motion.div layoutId="active-dot" className="absolute top-4 right-4 w-2 h-2 bg-blue-500 rounded-full" />}
              </button>
              <button onClick={() => setViewMode('filtered')} className={`p-6 rounded-2xl border transition-all text-left relative overflow-hidden group ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-500 shadow-[0_0_20px_rgba(234,88,12,0.15)]' : 'bg-gray-800/40 border-gray-700 hover:border-gray-600'}`}>
                <div className={`text-4xl font-black mb-1 ${viewMode === 'filtered' ? 'text-orange-400' : 'text-white'}`}>{filteredFrames.length}</div>
                <div className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Filtered</div>
                {viewMode === 'filtered' && <motion.div layoutId="active-dot" className="absolute top-4 right-4 w-2 h-2 bg-orange-500 rounded-full" />}
              </button>
            </div>
          </section>
        </div>

        {/* Dynamic Gallery Section */}
        <div className="lg:col-span-7 flex flex-col gap-6">
          <div className="bg-gray-900/30 p-6 rounded-3xl border border-gray-800/50 flex items-center justify-between backdrop-blur-xl sticky top-4 z-40">
            <h2 className="text-2xl font-black text-white capitalize flex items-center gap-4">
              <span className={`w-3 h-3 rounded-full shadow-[0_0_10px_currentColor] ${viewMode === 'valid' ? 'text-blue-500 bg-blue-500' : 'text-orange-500 bg-orange-500'}`} />
              {viewMode} Inventory
            </h2>
            <div className="flex items-center gap-4">
              {selectedIds.size > 0 && (
                <div className="flex gap-3">
                  {anySelectedIsRedacted && (
                    <button 
                      onClick={handleUndoSelectedRedaction}
                      className="px-5 py-2.5 rounded-2xl text-orange-400 hover:text-white hover:bg-orange-600/20 text-[10px] uppercase font-black shadow-2xl transition-all border border-orange-600/30 flex items-center gap-3 backdrop-blur-md"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
                      UNDO BLUR
                    </button>
                  )}
                  <button 
                    onClick={autoBlurSelected} 
                    disabled={status === ProcessingStatus.AUTO_BLURRING}
                    className={`px-6 py-2.5 rounded-2xl text-white text-[10px] uppercase font-black shadow-2xl transition-all flex items-center gap-3 ${status === ProcessingStatus.AUTO_BLURRING ? 'bg-purple-600/40 text-purple-200 border border-purple-600/30' : 'bg-purple-600 hover:bg-purple-500 active:scale-95 shadow-[0_0_20px_rgba(147,51,234,0.3)]'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                    {status === ProcessingStatus.AUTO_BLURRING ? 'REDACTING PII...' : 'SCAN & BLUR PII'}
                  </button>
                </div>
              )}
              <button disabled={selectedIds.size === 0 || isDownloading} onClick={downloadSelected} className={`px-6 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all ${selectedIds.size === 0 ? 'bg-gray-800 text-gray-600 cursor-not-allowed border border-gray-700' : 'bg-emerald-600 text-white hover:bg-emerald-500 shadow-[0_0_25px_rgba(16,185,129,0.3)] active:scale-95'}`}>
                {isDownloading ? 'COMPRESSING...' : `EXPORT (${selectedIds.size})`}
              </button>
            </div>
          </div>

          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={(id) => setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; })}
              onToggleAll={(sel) => setSelectedIds(sel ? new Set(activeFrames.map(f => f.id)) : new Set())}
              onDelete={(id) => setRawCandidates(prev => prev.filter(f => f.id !== id))}
              onView={setPreviewFrame}
              onRestore={viewMode === 'filtered' ? moveFilteredToValid : undefined}
              onUndoBlur={handleUndoRedaction}
              onRefine={() => {}}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {previewFrame && (
          <RedactionViewer 
            frame={previewFrame} 
            onClose={() => setPreviewFrame(null)} 
            onSave={async (id, rects) => {
               // Always save against original source for quality
               const redactedUrl = await applyRedaction(previewFrame.originalDataUrl, rects);
               setRawCandidates(prev => prev.map(f => f.id === id ? { ...f, dataUrl: redactedUrl, redacted: true } : f));
               setPreviewFrame(null);
            }} 
          />
        )}
      </AnimatePresence>

      <canvas ref={canvasRef} className="hidden" />

      {/* Manual Capture FAB */}
      <div className="fixed bottom-10 right-10 z-[100]">
        <button onClick={handleManualSnapshot} className="w-20 h-20 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center text-white border-4 border-white/10 shadow-[0_10px_40px_rgba(37,99,235,0.4)] transition-all active:scale-90 group">
          <svg className="w-10 h-10 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
        </button>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import * as ReactWindow from 'react-window';
import _AutoSizer from 'react-virtualized-auto-sizer';
import { motion, AnimatePresence } from 'framer-motion';
import { ExtractedFrame } from '../types';

const List = (ReactWindow as any).FixedSizeList;
const AutoSizer = _AutoSizer as any;

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  selectedIds: Set<string>;
  onToggleSelection: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onDelete: (id: string) => void;
  onView: (frame: ExtractedFrame) => void;
  onRestore?: (id: string) => void;
  onUndoBlur?: (id: string) => void;
  onRefine: (frame: ExtractedFrame) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ 
  frames, 
  selectedIds, 
  onToggleSelection, 
  onToggleAll,
  onDelete,
  onView,
  onRestore,
  onUndoBlur
}) => {
  const allSelectedInCurrentView = frames.length > 0 && frames.every(f => selectedIds.has(f.id));

  const getGridConfig = (containerWidth: number) => {
    if (containerWidth < 640) return { columns: 1, gap: 24 };
    if (containerWidth < 1024) return { columns: 2, gap: 32 };
    if (containerWidth < 1440) return { columns: 2, gap: 32 };
    return { columns: 3, gap: 32 };
  };

  const FrameItem = ({ frame, isSelected }: { frame: ExtractedFrame, isSelected: boolean }) => {
    const isFiltered = !!frame.filterReason;

    return (
      <motion.div layout className={`group relative bg-gray-900 rounded-[2rem] overflow-hidden border transition-all duration-500 shadow-2xl h-full flex flex-col ${isSelected ? 'border-blue-500 ring-[12px] ring-blue-500/10' : 'border-gray-800 hover:border-gray-600'}`}>
        <div className="aspect-video bg-gray-950 relative overflow-hidden flex-shrink-0 cursor-pointer" onClick={() => onToggleSelection(frame.id)}>
          <img src={frame.dataUrl} alt="Screen" className={`w-full h-full object-contain transition-transform duration-1000 ease-out ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`} loading="lazy" />

          {/* Checkbox Overlay */}
          <div className={`absolute top-5 left-5 w-7 h-7 rounded-xl border-2 flex items-center justify-center transition-all backdrop-blur-xl ${isSelected ? 'bg-blue-600 border-blue-400 shadow-[0_0_15px_rgba(37,99,235,0.4)]' : 'bg-black/40 border-white/20 hover:border-white/40'}`}>
             {isSelected && <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>}
          </div>

          {/* Status Badges */}
          <div className="absolute top-5 right-5 flex flex-col gap-2 items-end">
             {frame.redacted && (
               <motion.span initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="bg-purple-600 text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-widest shadow-2xl border border-purple-400/30">
                 SHIELD ACTIVE
               </motion.span>
             )}
             {isFiltered ? (
               <span className="bg-orange-600/90 text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-widest shadow-2xl border border-orange-400/30 backdrop-blur-md">{frame.filterReason}</span>
             ) : (
               <span className="bg-emerald-600/90 text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-widest shadow-2xl border border-emerald-400/30 backdrop-blur-md">VALIDATED</span>
             )}
          </div>

          <div className="absolute bottom-4 left-4 bg-black/70 backdrop-blur-xl text-[10px] font-black font-mono py-1 px-3 rounded-xl border border-white/10 text-blue-400 shadow-2xl">
            {frame.timestamp.toFixed(2)}s
          </div>
        </div>

        <div className="p-4 flex items-center justify-between bg-gray-900 mt-auto border-t border-gray-800/50">
          <div className="flex gap-2">
            <button onClick={(e) => { e.stopPropagation(); onView(frame); }} title="Analyze & Redact" className="p-2.5 bg-gray-800 hover:bg-blue-600/20 rounded-xl transition-all text-blue-400 border border-gray-700/50 active:scale-90">
